// src/analyze-news/analyze-news.service.ts
import {
    BadRequestException,
    Injectable,
    NotFoundException,
} from '@nestjs/common';
import { InjectModel } from '@nestjs/mongoose';
import { Model, Types } from 'mongoose';
import { AnalyzeNews, AnalyzeNewsDocument } from './analyze-news.schema';
import { CreateAnalyzeNewsDto } from './dto/create-analyze-news.dto';
import { Direction } from 'src/trading-plan/trading-plan.enum';
import { PersistImageService } from 'src/common/persist-image.service';
import { RealtimeGateway } from 'src/real-time/realtime.gateway';
import { WebPushSubService } from 'src/web-push-sub/web-push-sub.service';
import { PushProducer } from 'src/queue/push.producer';
import { AwsS3Service } from 'src/storage/aws-s3.service';

type MulterFile = Express.Multer.File;

export type AnalyzeNewsLean = {
    _id: Types.ObjectId;
    title: string;
    pair?: string;
    impact: string;
    description: string;
    thumbnailUrl?: string;
    createdAt?: Date;
    updatedAt?: Date;
};
const MAX_ANALYZE_NEWS = 6;
const MAX_THUMBNAIL_BYTES = 8 * 1024 * 1024;

@Injectable()
export class AnalyzeNewsService {
    constructor(
        @InjectModel(AnalyzeNews.name)
        private readonly newsModel: Model<AnalyzeNewsDocument>,
        private readonly s3: AwsS3Service,
        private readonly img: PersistImageService,
        private readonly realtime: RealtimeGateway,
        private readonly pushProducer: PushProducer,
        private readonly webPushSubService: WebPushSubService,
    ) {}

    async create(dto: CreateAnalyzeNewsDto, file?: MulterFile) {
        if (dto.impact == null) dto.impact = Direction.Bearish;

        const finalThumb = await this.resolveThumbnailUrl(dto, file);

        // 2) Build payload with the *persisted* URL (avoid saving empty string)
        const payload: CreateAnalyzeNewsDto = {
            ...dto,
            thumbnailUrl: finalThumb || undefined,
        };

        let created!: AnalyzeNewsLean;

        // 3) Enforce MAX=6 and create doc (transactional, with fallback)
        const session = await this.newsModel.db.startSession();
        try {
            await session.withTransaction(async () => {
                const count = await this.newsModel
                    .countDocuments({})
                    .session(session);
                const toDelete = Math.max(0, count - MAX_ANALYZE_NEWS + 1);

                if (toDelete > 0) {
                    const oldest = await this.newsModel
                        .find({})
                        .sort({ createdAt: 1 })
                        .limit(toDelete)
                        .select({ _id: 1 })
                        .lean()
                        .session(session);

                    const ids = oldest.map((d) => d._id);
                    if (ids.length) {
                        await this.newsModel
                            .deleteMany({ _id: { $in: ids } })
                            .session(session);
                    }
                }
                const [doc] = await this.newsModel.create([payload], {
                    session,
                });
                created = await this.newsModel
                    .findById(doc._id)
                    .lean<AnalyzeNewsLean>()
                    .session(session)
                    .orFail();
            });
        } catch (err: any) {
            // Standalone Mongo fallback (no replica set)
            if (
                String(err?.message || '').includes(
                    'Transaction numbers are only allowed on a replica set',
                )
            ) {
                const count = await this.newsModel.countDocuments({});

                const toDelete = Math.max(0, count - MAX_ANALYZE_NEWS + 1);

                if (toDelete > 0) {
                    const oldest = await this.newsModel
                        .find({})
                        .sort({ createdAt: 1 })
                        .limit(toDelete)
                        .select({ _id: 1 })
                        .lean();

                    const ids = oldest.map((d) => d._id);
                    if (ids.length) {
                        await this.newsModel.deleteMany({ _id: { $in: ids } });
                    }
                }

                // IMPORTANT: use payload (NOT raw dto)
                const doc = await this.newsModel.create(payload);
                created = await this.newsModel
                    .findById(doc._id)
                    .lean<AnalyzeNewsLean>()
                    .orFail();
            } else {
                throw err;
            }
        } finally {
            session.endSession();
        }

        // ---- Push notification (tiny payload; SW will fetch full content by id) ----
        try {
            const tinyPayload = {
                title: 'New Analysis 📰',
                body: created.pair
                    ? `${created.title} • ${created.pair} • ${created.impact}`
                    : `${created.title} • ${created.impact}`,
            };

            // Exclude author if provided on dto (optional)
            const excludeId: Types.ObjectId | null = null;

            // Get recipients (all active users, optionally excluding author).
            const recipients = await this.webPushSubService.getUserIdsExcept(
                excludeId ?? new Types.ObjectId('000000000000000000000000'), // excludes no one if author unknown
            );

            console.log('=======AnalyzeNews.create', recipients);

            if (recipients.length) {
                await this.pushProducer.enqueueSendToUsers(
                    recipients,
                    tinyPayload,
                    { ttl: 3600, chunkSize: 500 },
                );
            }
        } catch (e) {
            // Don’t block creation on push failures
            console.warn('[AnalyzeNews.create] push enqueue failed:', e);
        }
        // ---------------------------------------------------------------------------

        this.realtime.publishBadge('news');

        return created;
    }

    async findAll() {
        return this.newsModel
            .find({})
            .sort({ createdAt: -1 })
            .lean<AnalyzeNewsLean[]>();
    }

    async findById(_id: Types.ObjectId) {
        const doc = await this.newsModel
            .findById(_id)
            .lean<AnalyzeNewsLean | null>();
        if (!doc) throw new NotFoundException('Analyze news not found');
        return doc;
    }

    async remove(_id: Types.ObjectId) {
        const deleted = await this.newsModel
            .findOneAndDelete({ _id })
            .lean<AnalyzeNewsLean | null>();
        if (!deleted) throw new NotFoundException('Analyze news not found');
        await this.deleteThumbnailIfNeeded(deleted.thumbnailUrl);
        return { ok: true, id: String(deleted._id) };
    }

    async update(
        _id: Types.ObjectId,
        dto: CreateAnalyzeNewsDto,
        file?: MulterFile,
    ) {
        const existing = await this.newsModel
            .findById(_id)
            .lean<AnalyzeNewsLean | null>();
        if (!existing) throw new NotFoundException('Analyze news not found');

        const finalThumb = await this.resolveThumbnailUrl(dto, file);

        const updated = await this.newsModel.findByIdAndUpdate(
            _id,
            {
                title: dto?.title,
                description: dto?.description,
                pair: dto?.pair,
                impact: dto?.impact,
                thumbnailUrl: finalThumb,
            },
            { new: true, lean: true },
        );

        if (!updated) throw new NotFoundException('Analyze news not found');
        if (existing.thumbnailUrl && existing.thumbnailUrl !== finalThumb) {
            await this.deleteThumbnailIfNeeded(existing.thumbnailUrl);
        }
        return updated;
    }

    async uploadThumbnailFile(
        file: MulterFile,
    ): Promise<{ thumbnailUrl: string }> {
        if (!file) throw new BadRequestException('FILE_REQUIRED');
        if (!file.buffer?.length) throw new BadRequestException('FILE_EMPTY');
        if (file.size > MAX_THUMBNAIL_BYTES)
            throw new BadRequestException('FILE_TOO_LARGE');
        if (!file.mimetype?.startsWith('image/'))
            throw new BadRequestException('FILE_NOT_IMAGE');

        const upload = await this.s3.uploadFile(file, {
            folder: 'analyze-news',
            cacheControl: 'public, max-age=31536000',
        });

        return { thumbnailUrl: upload.url };
    }

    private async resolveThumbnailUrl(
        dto: CreateAnalyzeNewsDto,
        file?: MulterFile,
    ): Promise<string> {
        if (file) {
            const { thumbnailUrl } = await this.uploadThumbnailFile(file);
            return thumbnailUrl;
        }

        let finalThumb = (dto.thumbnailUrl ?? '').trim();

        if (finalThumb) {
            try {
                const up = await this.img.uploadFromUrl(finalThumb, {
                    folder: 'analyze-news',
                });
                finalThumb = up.secure_url; // <- permanent URL
            } catch (e) {
                console.warn(
                    '[AnalyzeNews.create] thumbnail persist failed:',
                    e,
                );
                finalThumb = '';
            }
        }

        return finalThumb;
    }

    private async deleteThumbnailIfNeeded(
        thumbnailUrl?: string,
    ): Promise<void> {
        if (!thumbnailUrl) return;
        try {
            await this.s3.deleteFileByUrl(thumbnailUrl);
        } catch (e) {
            console.warn('[AnalyzeNews] delete thumbnail failed:', e);
        }
    }
}

// src/analyze-news/dto/create-analyze-news.dto.ts
import {
    IsArray,
    ArrayUnique,
    IsEnum,
    IsOptional,
    IsString,
    Length,
    MaxLength,
    IsUrl,
} from 'class-validator';
import { Direction, Pair } from 'src/trading-plan/trading-plan.enum';

export class CreateAnalyzeNewsDto {
    @IsString()
    @Length(1, 200)
    title!: string;

    @IsOptional()
    pair?: Pair;

    @IsOptional()
    @IsEnum(Direction)
    impact?: Direction;

    @IsOptional()
    description: string;

    @IsOptional()
    @IsUrl({ require_tld: false })
    @MaxLength(500)
    thumbnailUrl?: string;
}

// src/app.module.ts

// ─── Core NestJS & Config ──────────────────────────────────────────────────────
import { Module } from '@nestjs/common';
import { ConfigModule, ConfigService } from '@nestjs/config';
import { APP_GUARD } from '@nestjs/core';
import type { Request } from 'express';

// ─── Validation & Environment ──────────────────────────────────────────────────
import { envValidationSchema } from './config/env.validation';
import { resolveExistingEnvFiles } from './config/env-files';

// ─── Database & Redis ─────────────────────────────────────────────────────────
import { MongooseModule } from '@nestjs/mongoose';
import type Redis from 'ioredis';
import { REDIS } from './redis/redis.constants';
import { RedisModule } from './redis/redis.module';

// ─── Security & Throttling ─────────────────────────────────────────────────────
import { ThrottlerModule, ThrottlerGuard, seconds } from '@nestjs/throttler';
import { ThrottlerStorageRedisService } from '@nest-lab/throttler-storage-redis';
import { sha256Hex } from './common/crypto/hash.util';

// ─── Logger ───────────────────────────────────────────────────────────────────
import { LoggerModule } from 'nestjs-pino';

// ─── Controllers & Services ───────────────────────────────────────────────────
import { AppController } from './app.controller';

// ─── Feature Modules ──────────────────────────────────────────────────────────
import { UserModule } from './user/user.module';
import { MailModule } from './mail/mail.module';
import { AuthModule } from './auth/auth.module';

// ─── Middleware ───────────────────────────────────────────────────────────────
import { JwtAuthGuard } from './auth/guard/jwt-auth.guard';
import { CsrfGuard } from './auth/guard/csrf.guard';
import { PlanModule } from './plan/plan.module';
import { TradingPlanModule } from './trading-plan/trading-plan.module';
import { WebPushSubModule } from './web-push-sub/web-push-sub.module';
import { TurnstileModule } from './turnstile/turnstile.module';
import { AnalyzeNewsModule } from './analyze-news/analyze-news.module';
import { RealtimeModule } from './real-time/real-time.module';
import { MembershipsModule } from './memberships/memberships.module';
import { CouponsModule } from './coupons/coupons.module';
import { QueueModule } from './queue/queue.module';
import { RolesGuard } from './auth/guard/roles.guard';
import { RetailerModule } from './retailer/retailer.module';
import { ScheduleModule } from '@nestjs/schedule';
import { OrderModule } from './order/order.module';
import { SubscriptionsModule } from './subscriptions/subscriptions.module';
import { StorageModule } from './storage/storage.module';
import { ProductsModule } from './products/products.module';
import { TradingModule } from './robots/trading/trading.module';
import { IndicatorModule } from './indicator/indicator.module';

const useRedisThrottle = process.env.NODE_ENV !== 'development';

@Module({
    imports: [
        // ─── Global Config ────────────────────────────────────────────────────────
        ConfigModule.forRoot({
            isGlobal: true,
            envFilePath: [
                `.env.${process.env.NODE_ENV || 'development'}`,
                '.env',
            ],
            ignoreEnvFile: false,
            expandVariables: true,
            cache: true,
            validationSchema: envValidationSchema,
            validationOptions: {
                abortEarly: false,
                allowUnknown: true,
                stripUnknown: false,
            },
        }),

        // ─── Logging (Pino) ───────────────────────────────────────────────────────
        LoggerModule.forRootAsync({
            inject: [ConfigService],
            useFactory: (cfg: ConfigService) => {
                const isDev = cfg.get('NODE_ENV') !== 'production';

                return {
                    pinoHttp: {
                        level:
                            cfg.get<string>('LOG_LEVEL') ??
                            (isDev ? 'debug' : 'info'),
                        transport: isDev
                            ? {
                                  target: 'pino-pretty',
                                  options: {
                                      singleLine: true,
                                      translateTime: 'SYS:standard',
                                      messageKey: 'msg',
                                  },
                              }
                            : undefined,

                        genReqId: (req) =>
                            (req.headers['x-request-id'] as string) ||
                            crypto.randomUUID(),

                        customProps: (req) => ({
                            reqId: (req as any).id,
                            userId: (req as any)?.user?.id,
                        }),

                        autoLogging: {
                            ignore: (req) =>
                                req.url === '/health' ||
                                req.url?.startsWith('/_next') ||
                                req.method === 'OPTIONS',
                        },

                        redact: {
                            paths: [
                                'req.headers.authorization',
                                'req.headers.cookie',
                                'req.body.password',
                                'req.body.*.password',
                            ],
                            censor: '[REDACTED]',
                        },
                    },
                };
            },
        }),

        // ─── Database (MongoDB) ───────────────────────────────────────────────────
        MongooseModule.forRootAsync({
            imports: [ConfigModule],
            inject: [ConfigService],
            useFactory: async (cs: ConfigService) => ({
                uri: cs.get<string>('MONGO_URI'),
            }),
        }),

        // ─── Redis & Throttling ───────────────────────────────────────────────────
        RedisModule,
        ThrottlerModule.forRootAsync({
            imports: useRedisThrottle ? [RedisModule] : [],
            inject: useRedisThrottle ? [REDIS] : [],
            useFactory: (redis?: Redis) => ({
                throttlers: [{ limit: 10, ttl: seconds(60) }], // 10 req/min
                ...(useRedisThrottle && redis
                    ? { storage: new ThrottlerStorageRedisService(redis) }
                    : {}),

                common: {
                    getTracker: async (req: Request) => {
                        const xff = (
                            req.headers['x-forwarded-for'] as string | undefined
                        )
                            ?.split(',')[0]
                            ?.trim();

                        const ip =
                            xff ||
                            (req.headers['cf-connecting-ip'] as
                                | string
                                | undefined) || // if Cloudflare
                            req.ip ||
                            req.socket.remoteAddress ||
                            'unknown';

                        const rawDev =
                            (req.headers['x-device-id'] as
                                | string
                                | undefined) ??
                            (req as any).cookies?.device_id ??
                            '';

                        const devHash =
                            rawDev && rawDev.length >= 8 && rawDev.length <= 128
                                ? sha256Hex(rawDev)
                                : 'no-dev';

                        return `${ip}|${devHash}`;
                    },
                },
            }),
        }),
        ScheduleModule.forRoot(),
        // ─── Feature Modules ──────────────────────────────────────────────────────
        UserModule,
        MailModule,
        AuthModule,
        PlanModule,
        TradingPlanModule,
        WebPushSubModule,
        TurnstileModule,
        AnalyzeNewsModule,
        RealtimeModule,
        MembershipsModule,
        CouponsModule,
        QueueModule,
        RetailerModule,
        OrderModule,
        SubscriptionsModule,
        StorageModule,
        ProductsModule,
        TradingModule,
        IndicatorModule,
    ],

    controllers: [AppController],

    providers: [
        { provide: APP_GUARD, useClass: ThrottlerGuard },
        { provide: APP_GUARD, useClass: JwtAuthGuard },
        { provide: APP_GUARD, useClass: RolesGuard },
        { provide: APP_GUARD, useClass: CsrfGuard },
    ],
})
export class AppModule {}

import {
    Body,
    Controller,
    Get,
    HttpCode,
    HttpStatus,
    Post,
    Req,
    UnauthorizedException,
    UseGuards,
    Res,
} from '@nestjs/common';
import type { Request, Response } from 'express';
import { Throttle } from '@nestjs/throttler';
import { AuthService } from './auth.service';
import { SignupDto } from './dto/signup.dto';
import { ApiSuccess } from 'src/common/types/api-response.type';
import { PublicUser } from 'src/common/types/public-user.type';
import { sha256Hex } from 'src/common/crypto/hash.util';
import { getClientIp } from 'src/common/auth/client-ip';
import { LoginDto } from './dto/login.dto';
import { LoginTelemetry } from 'src/common/types/login-telemetry.type';
import type { AuthRequest } from 'src/common/types/auth-request.type';
import { UserService } from 'src/user/user.service';
import { AuthGuard } from '@nestjs/passport';
import { Public } from './guard/public.decorator';
import { SkipCsrf } from './guard/skip-csrf.decorator';
import crypto from 'crypto';
import { GoogleUserPayload } from 'src/common/types/google-auth.type';
import { cookieBase } from 'src/common/cookies/cookie.util';
import { TurnstileAction } from 'src/turnstile/turnstile.decorator';
import { VerifyEmailDto } from './dto/verify-email.dto';
import { ResendVerificationDto } from './dto/resend-verification.dto';
import { TurnstileGuard } from 'src/turnstile/turnstile.guard';
import { ResetPasswordDto } from './dto/reset-password.dto';

@Controller('auth')
export class AuthController {
    constructor(
        private readonly auth: AuthService,
        private readonly users: UserService,
    ) {}

    @Public()
    @TurnstileAction('register')
    @UseGuards(TurnstileGuard)
    @Post('signup')
    @Throttle({ default: { limit: 5, ttl: 60_000 } })
    @HttpCode(HttpStatus.CREATED)
    async signup(
        @Body() dto: SignupDto,
        @Req() req: Request,
    ): Promise<ApiSuccess<PublicUser>> {
        const userAgent =
            (req.headers['user-agent']?.toString() ?? '').slice(0, 200) || null;
        const referer =
            (req.headers['referer']?.toString() ?? '').slice(0, 200) || null;

        const deviceIdHeader =
            (req.headers['x-client-device-id'] as string | undefined) ??
            (req.headers['x-device-id'] as string | undefined);
        const deviceIdHash =
            deviceIdHeader &&
            deviceIdHeader.length >= 8 &&
            deviceIdHeader.length <= 128
                ? sha256Hex(deviceIdHeader)
                : null;

        const ip = getClientIp(req);
        const ipHash = ip ? sha256Hex(ip) : null;

        const user = await this.auth.signup(dto, {
            userAgent,
            referer,
            deviceIdHash,
            ipHash,
            submittedAtMs: Date.now(),
        });

        return {
            success: true,
            statusCode: HttpStatus.CREATED,
            code: 'USER_CREATED',
            message: 'Signup successful',
            data: user,
            timestamp: new Date().toISOString(),
            path: req.url,
        };
    }

    @Public()
    @TurnstileAction('login')
    @UseGuards(TurnstileGuard)
    @Post('login')
    @Throttle({ default: { limit: 5, ttl: 60_000 } })
    @HttpCode(HttpStatus.OK)
    async login(
        @Body() dto: LoginDto,
        @Req() req: Request,
        @Res({ passthrough: true }) res: Response,
    ): Promise<
        ApiSuccess<{
            tokenType: 'Bearer';
            accessToken: string;
            expiresIn: number;
            user?: PublicUser;
        }>
    > {
        const ip = getClientIp(req);
        const ua = (req.headers['user-agent']?.toString() ?? '').slice(0, 200);
        const deviceId =
            (req.headers['x-client-device-id'] as string | undefined) ??
            (req.headers['x-device-id'] as string | undefined);

        const telemetry: LoginTelemetry = {
            ip,
            userAgent: ua || null,
            deviceId: deviceId || null,
            deviceIdHash:
                deviceId && deviceId.length >= 8 && deviceId.length <= 128
                    ? sha256Hex(deviceId)
                    : null,
        };

        const { expiresIn, accessToken } = await this.auth.login(
            dto,
            telemetry,
        );

        const base = cookieBase();

        // HttpOnly auth cookie (host-only, strict in prod)
        res.cookie('accessToken', accessToken, {
            ...base,
            httpOnly: true,
            maxAge: expiresIn * 1000,
        });

        // CSRF token (readable by JS, same attributes otherwise)
        const csrf = crypto.randomBytes(32).toString('hex');
        res.cookie('XSRF-TOKEN', csrf, {
            ...base,
            httpOnly: false,
            maxAge: expiresIn * 1000,
        });

        return {
            success: true,
            statusCode: HttpStatus.OK,
            code: 'LOGIN_OK',
            message: 'Login successful',
            timestamp: new Date().toISOString(),
            path: req.url,
        };
    }

    @Get('me')
    async getMe(@Req() req: AuthRequest): Promise<ApiSuccess<PublicUser>> {
        const uid = req?.user?.userId;
        if (!uid) throw new UnauthorizedException('AUTH_REQUIRED');

        // Important: return a plain object, not a Mongoose Document
        const user = await this.users.findById(uid);
        if (!user) throw new UnauthorizedException('USER_NOT_FOUND');

        // Build a plain payload — avoid spreading a Document
        const data: PublicUser = {
            _id: String(user._id),
            email: user.email,
            firstName: user?.firstName,
            lastName: user?.lastName,
            role: user?.role,
            emailVerified: false,
            photoURL: user.photoURL,
        };

        return {
            success: true,
            data,
            statusCode: HttpStatus.OK,
            code: 'ME',
            message: 'Successful',
            timestamp: new Date().toISOString(),
            path: req.url,
        };
    }

    @Public()
    @Post('verify-email')
    @Throttle({ default: { limit: 10, ttl: 60_000 } }) // 10 requests/min per IP (tune as you like)
    @HttpCode(HttpStatus.NO_CONTENT)
    async verifyEmail(@Body() dto: VerifyEmailDto): Promise<void> {
        // await this.auth.verifyEmail(dto.token);
    }

    @Public()
    @Post('resend-verification')
    @Throttle({ default: { limit: 5, ttl: 60_000 } }) // 5/min
    @HttpCode(HttpStatus.OK)
    async resendVerification(
        @Body() dto: ResendVerificationDto,
        @Req() req: Request,
    ) {
        await this.auth.resendVerification(
            dto.email,
            req.ip,
            req.get('user-agent') ?? undefined,
        );
        return {
            message:
                'If an account exists, we’ve sent a new verification email.',
        };
    }

    @Public()
    @SkipCsrf()
    @Get('google')
    @Throttle({ default: { limit: 10, ttl: 60_000 } })
    @UseGuards(AuthGuard('google'))
    async googleAuth() {
        // passport triggers redirect, nothing to do here
    }

    @Public()
    @SkipCsrf()
    @Get('google/callback')
    @Throttle({ default: { limit: 10, ttl: 60_000 } })
    @UseGuards(AuthGuard('google'))
    async googleCallback(
        @Req() req: Request,
        @Res({ passthrough: true }) res: Response,
    ) {
        // state was injected by GoogleStrategy.authorizationParams(req)

        // req.user comes from GoogleStrategy.validate()
        const { accessToken, expiresIn } = await this.auth.handleGoogleLogin(
            req.user as GoogleUserPayload,
        );

        const base = cookieBase();

        // HttpOnly auth cookie
        res.cookie('accessToken', accessToken, {
            ...base,
            httpOnly: true,
            maxAge: expiresIn * 1000,
        });

        // CSRF token
        const csrf = crypto.randomBytes(32).toString('hex');
        res.cookie('XSRF-TOKEN', csrf, {
            ...base,
            httpOnly: false,
            maxAge: expiresIn * 1000,
        });

        return res.redirect('/');
    }

    @Post('logout')
    @Throttle({ default: { limit: 10, ttl: 60_000 } })
    @HttpCode(HttpStatus.OK)
    async logout(
        @Req() req: Request,
        @Res({ passthrough: true }) res: Response,
    ) {
        const base = cookieBase();

        res.clearCookie('accessToken', { ...base, httpOnly: true });
        res.clearCookie('XSRF-TOKEN', { ...base, httpOnly: false });

        return {
            success: true,
            statusCode: HttpStatus.OK,
            code: 'LOGOUT_OK',
            message: 'Logged out',
            data: null,
            timestamp: new Date().toISOString(),
            path: req.url,
        };
    }

    @Public()
    @TurnstileAction('forgot-password')
    @Post('forgot-password')
    @HttpCode(HttpStatus.OK)
    @Throttle({ default: { limit: 3, ttl: 60_000 } })
    async forgotPassword(@Body() dto: { email: string }, @Req() req: Request) {
        const ip = getClientIp(req) ?? undefined; // 👈 coerce null → undefined
        const ua =
            (req.headers['user-agent']?.toString() ?? '').slice(0, 200) ||
            undefined;

        await this.auth.requestPasswordReset(
            dto?.email?.toString().trim() ?? '',
            ip,
            ua,
        );

        return {
            message:
                'If an account exists, we’ve sent an email with a reset link.',
        };
    }

    @Public()
    @TurnstileAction('reset-password')
    @SkipCsrf()
    @Post('reset-password')
    @HttpCode(HttpStatus.OK)
    async resetPassword(@Body() dto: ResetPasswordDto) {
        await this.auth.resetPassword(dto.token, dto.password);
        return { message: 'Password reset successful.' };
    }
}

// src/auth/auth.service.ts
import {
    Injectable,
    Logger,
    InternalServerErrorException,
    UnauthorizedException,
    BadRequestException,
    ConflictException,
    ForbiddenException,
} from '@nestjs/common';
import { UserService } from '../user/user.service';
import { SignupDto } from './dto/signup.dto';
import { SignInMethod } from 'src/auth/signin-method.enum';
import type { SignupMeta } from 'src/user/user.schema';
import { PublicUser } from 'src/common/types/public-user.type';
import { maskEmail } from 'src/common/utils/email.util';
import * as argon2 from 'argon2';
import { fromB64Env } from 'src/common/utils/env.util';
import { JwtService } from '@nestjs/jwt';
import { subnet24 } from 'src/common/risk/risk.utils';
import { LoginDto } from './dto/login.dto';
import { LoginTelemetry } from 'src/common/types/login-telemetry.type';
import { formatRemainingLockTime } from 'src/common/utils/time.util';
import { GoogleUserPayload } from 'src/common/types/google-auth.type';
import { Role } from 'src/user/user.enum';
import { InjectModel } from '@nestjs/mongoose';
import {
    EmailVerificationToken,
    EmailVerificationTokenDocument,
} from './email-verification-token.schema';
import { MailService } from 'src/mail/mail.service';
import { ConfigService } from '@nestjs/config';
import { Model, Types } from 'mongoose';
import { sha256Hex } from 'src/common/crypto/hash.util';
import { randomBytes } from 'crypto';
import {
    PasswordResetToken,
    PasswordResetTokenDocument,
} from './password-reset-token.schema';
import { PushProducer } from 'src/queue/push.producer';

@Injectable()
export class AuthService {
    private readonly logger = new Logger(AuthService.name);

    private readonly ACCESS_TTL_SEC = Number(process.env.JWT_ACCESS_TTL ?? 900); // 15m
    private readonly JWT_ALG =
        (process.env.JWT_ALG as 'RS256' | 'HS256' | undefined) ?? 'RS256';
    private readonly JWT_ISSUER = process.env.JWT_ISSUER;
    private readonly VERIFY_TTL_MS = 24 * 60 * 60 * 1000;
    private readonly RESET_TTL_MS =
        Number(process.env.PW_RESET_TTL_MIN ?? 20) * 60 * 1000; // 20m default

    private appHost!: string;

    constructor(
        private readonly users: UserService,
        private readonly jwt: JwtService,
        @InjectModel(EmailVerificationToken.name)
        private readonly verifyModel: Model<EmailVerificationTokenDocument>,
        @InjectModel(PasswordResetToken.name)
        private readonly pwResetModel: Model<PasswordResetTokenDocument>,
        private readonly mail: MailService,
        private readonly config: ConfigService,
        private readonly pushProducer: PushProducer,
    ) {
        this.appHost =
            this.config.get<string>('FRONTEND_URL') ||
            'https://app.example.com';
    }

    private newToken() {
        return randomBytes(32).toString('base64url');
    }

    private async issueAndSendEmailVerification(
        userId: Types.ObjectId,
        email: string,
        ip?: string,
        ua?: string,
    ) {
        // invalidate any active tokens
        await this.verifyModel.updateMany(
            { userId, usedAt: null, expiresAt: { $gt: new Date() } },
            { $set: { expiresAt: new Date() } },
        );

        const raw = this.newToken();
        const tokenHash = sha256Hex(raw);

        await this.verifyModel.create({
            userId,
            tokenHash,
            expiresAt: new Date(Date.now() + this.VERIFY_TTL_MS),
            issuedIp: ip,
            issuedUa: ua,
        });
        const link = `${this.appHost}/verify-email?token=${raw}`;
        try {
            await this.mail.sendEmailVerification(email, link);
        } catch (e) {
            // best-effort: don't fail signup just because email send errored
            this.logger.warn(
                `sendEmailVerification failed for ${maskEmail(email)}: ${(e as Error)?.message}`,
            );
        }
    }

    private async issueAndSendPasswordReset(
        userId: Types.ObjectId,
        email: string,
        ip?: string,
        ua?: string,
    ) {
        await this.pwResetModel.updateMany(
            { userId, usedAt: null, expiresAt: { $gt: new Date() } },
            { $set: { expiresAt: new Date() } },
        );

        const raw = this.newToken();
        const tokenHash = sha256Hex(raw);

        await this.pwResetModel.create({
            userId,
            tokenHash,
            expiresAt: new Date(Date.now() + this.RESET_TTL_MS),
            issuedIp: ip,
            issuedUa: ua,
            reason: 'forgot',
        });

        // Prefer path-style link; keep ?email to enable one-click resend UX on the page
        const link = `${this.appHost}/reset-password/${raw}?email=${encodeURIComponent(email)}`;

        try {
            await this.mail.sendPasswordReset(email, link);
        } catch (e) {
            this.logger.warn(
                `sendPasswordReset failed for ${maskEmail(email)}: ${(e as Error)?.message}`,
            );
        }
    }

    async signup(
        dto: SignupDto,
        reqMeta: Partial<SignupMeta> = {},
    ): Promise<PublicUser> {
        const email = this.users.normalizeEmail(dto.email);

        const existing = await this.users.findByEmail(email);

        if (existing?.isBanned) {
            throw new ForbiddenException('This account is banned.');
        }

        const isExisting = await this.users.findByEmail(email);
        if (isExisting) {
            throw new ConflictException('Email already registered!');
        }

        try {
            this.logger.debug(`Signup attempt email=${maskEmail(email)}`);

            const user = await this.users.create({
                firstName: dto.firstName.trim(),
                lastName: dto.lastName?.trim(),
                email,
                password: dto.password, // hashed in UserService.create
                signInMethod: SignInMethod.Password,
                emailVerified: false,
                signupMeta: {
                    userAgent: reqMeta.userAgent ?? null,
                    referer: reqMeta.referer ?? null,
                    deviceIdHash: reqMeta.deviceIdHash ?? null,
                    ipHash: reqMeta.ipHash ?? null,
                    renderedAtMs: reqMeta.renderedAtMs ?? null,
                    submittedAtMs: reqMeta.submittedAtMs ?? Date.now(),
                },
            });

            // NEW: issue token + send verification email (best-effort)
            await this.issueAndSendEmailVerification(
                new Types.ObjectId((user as any)._id ?? (user as any).id),
                user.email,
                undefined, // pass raw IP if you capture it elsewhere
                reqMeta.userAgent ?? undefined,
            );

            // fire-and-forget: enqueue a tiny welcome push for connected clients
            this.pushProducer
                .enqueueSendToUsers(
                    [new Types.ObjectId((user as any)._id ?? (user as any).id)],
                    { type: 'welcome', ts: Date.now() },
                    { ttl: 3600, dedupe: true },
                )
                .catch((e) =>
                    this.logger.debug(
                        `welcome push enqueue failed: ${e?.message}`,
                    ),
                );

            const publicUser: PublicUser = {
                _id: String((user as any).id ?? (user as any)._id),
                email: user.email,
                firstName: user.firstName,
                lastName: user.lastName,
                role: user.role as any,
                emailVerified: user.emailVerified || false,
            };

            this.logger.log(
                `Signup success id=${publicUser._id} email=${maskEmail(publicUser.email)}`,
            );

            return publicUser;
        } catch (err: any) {
            if (err?.status && err?.response) {
                this.logger.warn(
                    `Signup rejected: ${err.status} ${JSON.stringify(err.response)}`,
                );
                throw err;
            }
            this.logger.error(
                `Signup failed for email=${maskEmail(dto.email)}: ${err?.message || err}`,
                err?.stack,
            );
            throw new InternalServerErrorException('Unable to create user');
        }
    }

    async login(
        dto: LoginDto,
        t?: LoginTelemetry,
    ): Promise<{
        tokenType: 'Bearer';
        accessToken: string;
        expiresIn: number;
    }> {
        const email = this.users.normalizeEmail(dto.email);

        const existing = await this.users.findByEmail(email);

        if (existing?.isBanned) {
            throw new ForbiddenException('This account is banned.');
        }

        try {
            const authDoc = await this.users.getAuthForLoginByEmail(email);

            if (!authDoc) {
                this.logger.warn(
                    `We couldn’t find an account with that email=${maskEmail(email)}`,
                );
                throw new UnauthorizedException(
                    'We couldn’t find an account with that email.Please check and try again.',
                );
            }

            if (authDoc?.signInMethod != SignInMethod.Password) {
                throw new BadRequestException(
                    `This account was created with ${authDoc?.signInMethod} sign-in.`,
                );
            }

            if (!authDoc?.passwordHash) {
                throw new UnauthorizedException('Invalid credentials');
            }

            // 🔒 already locked? bail out early
            if (this.users.isLocked(authDoc)) {
                const remaining = formatRemainingLockTime(
                    new Date(authDoc.lockedUntil!),
                );
                throw new UnauthorizedException(
                    `Too many login attempts. Please try again in ${remaining}.`,
                );
            }

            // ✅ check password
            const ok = await argon2.verify(authDoc.passwordHash, dto.password);
            if (!ok) {
                // wrong password → count towards lock
                await this.users.recordFailedLogin(String(authDoc._id), {
                    maxAttempts: 5,
                    lockMs: 10 * 60 * 1000,
                });

                this.logger.warn(
                    JSON.stringify({
                        evt: 'login_failed',
                        email: maskEmail(email),
                        ip_subnet24: t?.ip ? subnet24(t.ip) : null,
                        deviceIdHash: t?.deviceIdHash ?? null,
                        reason: 'bad_password',
                    }),
                );

                throw new UnauthorizedException(
                    'The password you entered is incorrect. Please try again or reset your password.',
                );
            }

            // 🚨 password is correct but email is NOT verified
            // if (!authDoc.emailVerified) {
            //   // Treat this as a "failed" attempt for locking purposes
            //   await this.users.recordFailedLogin(String(authDoc._id), {
            //     maxAttempts: 5,                 // you can tune this separately if you want
            //     lockMs: 10 * 60 * 1000,         // e.g. 10 minutes
            //   });

            //   this.logger.warn(
            //     JSON.stringify({
            //       evt: 'login_failed',
            //       email: maskEmail(email),
            //       ip_subnet24: t?.ip ? subnet24(t.ip) : null,
            //       deviceIdHash: t?.deviceIdHash ?? null,
            //       reason: 'email_not_verified',
            //     }),
            //   );

            //   // try to resend verification email
            //   try {
            //     await this.issueAndSendEmailVerification(
            //       new (require('mongoose').Types.ObjectId)(String(authDoc._id)),
            //       authDoc.email,
            //       undefined,
            //     );
            //   } catch (e) {
            //     this.logger.warn(
            //       `auto-resend verify failed for ${maskEmail(authDoc.email)}: ${(e as Error)?.message}`,
            //     );
            //   }

            //   // user will hit the "Too many login attempts" branch once locked
            //   throw new UnauthorizedException(
            //     'Please verify your email to continue. We just sent you a new verification link.',
            //   );
            // }

            // 🎉 fully OK: verified + correct password
            await this.users.recordSuccessfulLogin(String(authDoc._id));

            const payload = {
                sub: String(authDoc._id),
                email: authDoc.email,
                role: authDoc.role,
                perms: (authDoc as any).perms ?? [],
                typ: 'access' as const,
            };

            const accessToken = await this.signAccessToken(payload);
            if (process.env.JWT_DEBUG_PAYLOAD === '1')
                this.debugJwt(accessToken);

            const user = this.users.toPublicUser(authDoc);

            this.logger.log(
                JSON.stringify({
                    evt: 'login_success',
                    _id: user._id,
                    email: maskEmail(user.email),
                    ip_subnet24: t?.ip ? subnet24(t.ip) : null,
                    deviceIdHash: t?.deviceIdHash ?? null,
                    role: authDoc.role,
                }),
            );

            return {
                tokenType: 'Bearer',
                accessToken,
                expiresIn: this.ACCESS_TTL_SEC,
            };
        } catch (err: any) {
            if (err?.status) throw err;
            this.logger.error(
                `Login error email=${maskEmail(email)}: ${err?.message || err}`,
                err?.stack,
            );
            throw new InternalServerErrorException('Unable to login');
        }
    }

    async handleGoogleLogin(google: GoogleUserPayload): Promise<{
        tokenType: 'Bearer';
        accessToken: string;
        expiresIn: number;
        user?: PublicUser;
    }> {
        if (!google?.googleId) {
            throw new UnauthorizedException('Invalid Google profile');
        }

        const userDoc = await this.users.upsertGoogleUser({
            googleId: google.googleId,
            email: google.email,
            firstName: google.firstName,
            lastName: google.lastName,
            photoURL: google.photoURL,
        });

        // enforce mapping (most Google signups are Students by default)
        const userRole = userDoc.role;

        // --- issue access JWT exactly like /login ---
        const payload = {
            sub: String(userDoc._id),
            email: userDoc.email,
            role: userRole,
            perms: (userDoc as any).perms ?? [],
            typ: 'access' as const,
        };

        const accessToken = await this.signAccessToken(payload);
        if (process.env.JWT_DEBUG_PAYLOAD === '1') this.debugJwt(accessToken);

        const publicUser = this.users.toPublicUser(userDoc);

        this.logger.log(
            JSON.stringify({
                evt: 'oauth_google_success',
                _id: publicUser._id,
                email: maskEmail(publicUser.email),
                role: userRole,
            }),
        );

        return {
            tokenType: 'Bearer',
            accessToken,
            expiresIn: this.ACCESS_TTL_SEC,
        };
    }

