import {
    Body,
    Controller,
    Get,
    HttpCode,
    HttpStatus,
    NotFoundException,
    Param,
    Patch,
    Post,
    Query,
    Req,
    UnauthorizedException,
} from '@nestjs/common';
import type { AuthRequest } from 'src/common/types/auth-request.type';
import type { ApiSuccess } from 'src/common/types/api-response.type';
import { IndicatorService } from './indicator.service';
import { RequestIndicatorDto } from './dto/request-indicator.dto';
import type { IndicatorDocument } from './indicator.schema';
import { PaginateIndicatorsDto } from './dto/paginate-indicators.dto';
import { Roles } from 'src/auth/decorators/roles.decorator';
import { Role } from 'src/user/user.enum';
import { UpdateIndicatorAdminDto } from './dto/update-indicator-admin.dto';

@Controller('indicator')
export class IndicatorController {
    constructor(private readonly indicators: IndicatorService) {}

    @Post('request')
    @HttpCode(HttpStatus.CREATED)
    async request(
        @Req() req: AuthRequest,
        @Body() dto: RequestIndicatorDto,
    ): Promise<ApiSuccess<IndicatorDocument>> {
        const userId = req.user?.userId;
        if (!userId) throw new UnauthorizedException('AUTH_REQUIRED');

        const indicator = await this.indicators.requestIndicator({
            userId,
            username: dto.username,
            notes: dto.notes,
        });

        return {
            success: true,
            statusCode: HttpStatus.CREATED,
            code: 'INDICATOR_REQUESTED',
            message: 'Indicator request submitted',
            data: indicator,
            timestamp: new Date().toISOString(),
            path: req.url,
        };
    }

    @Get()
    @Roles(Role.Admin)
    async list(@Query() query: PaginateIndicatorsDto) {
        const result = await this.indicators.paginate(query);

        // convenience: surface user names for tables
        const docs = result.docs.map((doc: any) => ({
            ...doc,
            userFirstName: doc.user?.firstName,
            userLastName: doc.user?.lastName,
            userEmail: doc.user?.email,
        }));

        return { ...result, docs };
    }

    @Patch(':id/admin')
    @Roles(Role.Admin)
    async adminUpdate(
        @Param('id') id: string,
        @Body() dto: UpdateIndicatorAdminDto,
        @Req() req: AuthRequest,
    ) {
        const indicator = await this.indicators.updateAdmin(
            id,
            dto,
            req.user?.userId,
        );
        return {
            success: true,
            statusCode: HttpStatus.OK,
            code: 'INDICATOR_UPDATED',
            message: 'Indicator updated',
            data: indicator,
            timestamp: new Date().toISOString(),
            path: req.url,
        };
    }

    @Get('me')
    @HttpCode(HttpStatus.OK)
    async me(@Req() req: AuthRequest): Promise<ApiSuccess<IndicatorDocument>> {
        const userId = req.user?.userId;
        if (!userId) throw new UnauthorizedException('AUTH_REQUIRED');

        const indicator = await this.indicators.getMyIndicator(userId);
        if (!indicator) throw new NotFoundException('INDICATOR_NOT_FOUND');

        return {
            success: true,
            statusCode: HttpStatus.OK,
            code: 'INDICATOR',
            message: 'Indicator fetched',
            data: indicator,
            timestamp: new Date().toISOString(),
            path: req.url,
        };
    }
}

import {
    Injectable,
    ConflictException,
    InternalServerErrorException,
    BadRequestException,
    NotFoundException,
    ForbiddenException,
} from '@nestjs/common';
import { InjectModel } from '@nestjs/mongoose';
import { FilterQuery, PaginateOptions, PaginateResult, Types } from 'mongoose';
import * as indicatorSchema from './indicator.schema';
import { UpdateIndicatorAdminDto } from './dto/update-indicator-admin.dto';
import * as membershipsSchema from 'src/memberships/memberships.schema';
import { MembershipStatus } from 'src/memberships/memberships.schema';

@Injectable()
export class IndicatorService {
    constructor(
        @InjectModel(indicatorSchema.Indicator.name)
        private readonly indicatorModel: indicatorSchema.IndicatorPaginateModel,
        @InjectModel(membershipsSchema.Membership.name)
        private readonly membershipModel: membershipsSchema.MembershipPaginateModel,
    ) {}

    async requestIndicator(params: {
        userId: string | Types.ObjectId;
        username: string;
        notes?: string;
    }): Promise<indicatorSchema.IndicatorDocument> {
        const user =
            typeof params.userId === 'string'
                ? new Types.ObjectId(params.userId)
                : params.userId;

        const username = (params.username ?? '').trim();
        if (!username) {
            throw new ConflictException('username is required');
        }

        const membership = await this.membershipModel.findOne({ user }).lean();
        if (!membership || membership.status !== MembershipStatus.Verified) {
            throw new ForbiddenException('Please join membership first');
        }

        try {
            return await this.indicatorModel.findOneAndUpdate(
                { user },
                {
                    $setOnInsert: { user },
                    $set: {
                        username, // <-- added
                        status: indicatorSchema.IndicatorStatus.Request,
                        ...(params.notes !== undefined
                            ? { notes: params.notes }
                            : {}),
                    },
                },
                { new: true, upsert: true },
            );
        } catch (err: any) {
            if (err?.code === 11000) {
                return this.indicatorModel.findOne({ user }).orFail();
            }
            throw new InternalServerErrorException(
                err?.message ?? 'Request failed',
            );
        }
    }

    async getMyIndicator(
        userId: string | Types.ObjectId,
    ): Promise<indicatorSchema.IndicatorDocument | null> {
        const user =
            typeof userId === 'string' ? new Types.ObjectId(userId) : userId;
        return this.indicatorModel.findOne({ user });
    }

    async paginate(query: {
        q?: string;
        status?: indicatorSchema.IndicatorStatus;
        page?: number;
        limit?: number;
    }): Promise<PaginateResult<indicatorSchema.IndicatorDocument>> {
        const { q, status, page = 1, limit = 20 } = query;

        const filter: FilterQuery<indicatorSchema.IndicatorDocument> = {};
        const or: FilterQuery<indicatorSchema.IndicatorDocument>[] = [];

        if (q && q.trim()) {
            const rx = new RegExp(this.escapeRegex(q.trim()), 'i');
            or.push({ username: rx }, { notes: rx });
        }

        if (or.length) {
            filter.$or = or;
        }

        if (status) {
            filter.status = status;
        }

        const options: PaginateOptions = {
            page: Number(page) || 1,
            limit: Number(limit) || 20,
            sort: { createdAt: -1 },
            lean: true,
            leanWithId: false,
            populate: [
                { path: 'user', select: '_id email firstName lastName' },
            ],
        };

        return this.indicatorModel.paginate(filter, options);
    }

    private escapeRegex(s: string) {
        return s.replace(/[.*+?^${}()|[\\]\\]/g, '\\$&');
    }

    async updateAdmin(
        id: string,
        dto: UpdateIndicatorAdminDto,
        updatedBy?: string,
    ) {
        if (!Types.ObjectId.isValid(id)) {
            throw new BadRequestException('INVALID_ID');
        }

        const indicator = await this.indicatorModel.findById(id).exec();
        if (!indicator) {
            throw new NotFoundException('INDICATOR_NOT_FOUND');
        }

        if (dto.status !== undefined) {
            indicator.status = dto.status;
        }

        if (dto.adminNotes !== undefined) {
            indicator.adminNotes = dto.adminNotes?.trim() || undefined;
        }

        if (updatedBy && Types.ObjectId.isValid(updatedBy)) {
            indicator.updatedBy = new Types.ObjectId(updatedBy);
        }

        await indicator.save();
        return this.indicatorModel.findById(indicator._id).lean().exec();
    }
}

