// src/mail/mail.service.ts
import { Injectable, Logger } from '@nestjs/common';
import { ConfigService } from '@nestjs/config';
import * as nodemailer from 'nodemailer';

@Injectable()
export class MailService {
    private readonly logger = new Logger(MailService.name);
    private transporter?: nodemailer.Transporter;
    private fromName: string;
    private fromEmail: string;

    constructor(private readonly config: ConfigService) {
        this.fromName = this.config.get<string>('MAIL_FROM_NAME') || 'No-Reply';
        this.fromEmail = this.config.get<string>('MAIL_FROM_EMAIL')!;

        // initialize once on startup; keep a single pooled transporter
        this.init().catch((err) => {
            this.logger.error('Mail transporter init failed', err);
        });
    }

    private async init() {
        const user = this.config.get<string>('MAIL_FROM_EMAIL');
        const pass = this.config.get<string>('GMAIL_APP_PASSWORD');

        if (!user || !pass) {
            this.logger.warn(
                'MAIL_FROM_EMAIL / GMAIL_APP_PASSWORD not set — Mail disabled.',
            );
            return;
        }

        this.transporter = nodemailer.createTransport({
            host: 'smtp.gmail.com',
            port: 587,
            secure: false,
            requireTLS: true,
            auth: { user, pass },
            pool: true,
            maxConnections: 3,
            maxMessages: 100,
            connectionTimeout: 15_000,
            greetingTimeout: 10_000,
            socketTimeout: 30_000,
        });

        try {
            await this.transporter.verify();
            this.logger.log('Nodemailer SMTP verified (Gmail App Password).');
        } catch (e) {
            this.logger.error('SMTP verify failed', e?.message);
            this.logger.error(e); // logs stack + code in many setups
            this.transporter = undefined;
        }
    }

    private ensureTransport() {
        if (!this.transporter) {
            throw new Error(
                'Mail transport unavailable (bad creds or init failed).',
            );
        }
        return this.transporter;
    }

    async send(opts: {
        to: string | string[];
        subject: string;
        text?: string;
        html?: string;
        replyTo?: string;
        headers?: Record<string, string>;
    }) {
        const tx = this.ensureTransport();

        // Provide minimal plain text if only HTML is supplied
        const text =
            opts.text ?? (opts.html ? this.stripHtml(opts.html) : undefined);

        const info = await tx.sendMail({
            from: `${this.fromName} <${this.fromEmail}>`,
            to: opts.to,
            subject: opts.subject,
            text,
            html: opts.html,
            replyTo: opts.replyTo,
            headers: {
                // Helps deliverability & unsub flows if you add them later
                'List-Unsubscribe-Post': 'List-Unsubscribe=One-Click',
                ...opts.headers,
            },
        });

        this.logger.debug(`Mail sent: ${info.messageId}`);
        return info;
    }

    // ---- Convenience methods you'll call from AuthService ----

    async sendEmailVerification(to: string, link: string) {
        const subject = 'Verify your email';
        const html = `
      <h2>Confirm your email</h2>
      <p>This link expires in 24 hours.</p>
      <p><a href="${link}" target="_blank" rel="noopener">Verify email</a></p>
      <p>If the button doesn’t work, paste this URL into your browser:</p>
      <p>${link}</p>
    `;
        return this.send({ to, subject, html });
    }

    async sendPasswordReset(to: string, link: string) {
        const subject = 'Reset your password';
        const html = `
    <span style="display:none!important;opacity:0;max-height:0;max-width:0;overflow:hidden;">
      Use this link to reset your password. It expires in 20 minutes.
    </span>
    <h2>Reset your password</h2>
    <p>This link expires in <strong>20 minutes</strong>.</p>
    <p>
      <a href="${link}" target="_blank" rel="noopener"
         style="display:inline-block;background:#4f46e5;color:#fff;padding:10px 16px;border-radius:8px;text-decoration:none">
        Reset password
      </a>
    </p>
    <p>If the button doesn’t work, paste this URL into your browser:</p>
    <p><a href="${link}" target="_blank" rel="noopener">${link}</a></p>
  `;
        return this.send({ to, subject, html });
    }

    // ---- tiny utility ----
    private stripHtml(html: string) {
        return html
            .replace(/<style[\s\S]*?<\/style>/gi, '')
            .replace(/<[^>]+>/g, '')
            .replace(/\s+/g, ' ')
            .trim();
    }
}

// main.ts
import { NestFactory } from '@nestjs/core';
import { AppModule } from './app.module';
import { Logger as PinoLogger } from 'nestjs-pino';
import { Logger, ValidationPipe } from '@nestjs/common';
import cookieParser from 'cookie-parser';
import { ConfigService } from '@nestjs/config';
import { NestExpressApplication } from '@nestjs/platform-express';
import type Redis from 'ioredis';
import { REDIS } from './redis/redis.constants';
import { HttpErrorFilter } from './common/http/http-error.filter'; // make sure path matches your file
import * as bodyParser from 'body-parser';
import helmet from 'helmet';
import hpp from 'hpp';
import compression from 'compression';
import { buildAllowedOrigins } from './common/security/origin';
import { SocketIoAdapter } from './real-time/socketio.adapter';
import { RequiredHeadersMiddleware } from './middleware/required-headers.middleware';

async function bootstrap() {
    const app = await NestFactory.create<NestExpressApplication>(AppModule, {
        bufferLogs: true,
    });

    app.set('trust proxy', 1);
    app.useLogger(app.get(PinoLogger));
    const logger = new Logger('Bootstrap');
    const config = app.get(ConfigService);

    // 👉 flag for environment
    const isProd = config.get('NODE_ENV') === 'production';

    // ---- build origins at RUNTIME ----
    const allowedOrigins = buildAllowedOrigins([
        config.get<string>('FRONTEND_URL'),
    ]);

    logger.log(`[CORS] allowed origins: ${allowedOrigins.join(', ')}`);

    app.enableCors({
        origin: allowedOrigins,
        credentials: true,
        methods: ['GET', 'HEAD', 'POST', 'PUT', 'PATCH', 'DELETE', 'OPTIONS'],
        allowedHeaders: [
            'content-type',
            'accept',
            'authorization',
            'x-csrf-token',
            'x-client-device-id',
            'x-device-id',
            'x-device-hash',
            'x-internal-signature',
            'x-internal-timestamp',
            'x-idempotency-key',
            'idempotency-key',
            'x-api-key',
            'x-request-id',
        ],
        optionsSuccessStatus: 204,
        maxAge: 86400,
    });

    // WebSocket adapter (after CORS config)
    const wsAdapter = new SocketIoAdapter(app, allowedOrigins);
    await wsAdapter.connectToRedisIfNeeded();
    app.useWebSocketAdapter(wsAdapter);

    app.useGlobalFilters(new HttpErrorFilter());

    // ---- Body parsers (must come before any middleware that inspects body/cookies) ----
    const express = app.getHttpAdapter().getInstance();
    express.use(
        '/retailer',
        bodyParser.json({
            limit: '1mb',
            verify: (req: any, _r, buf) => {
                req.rawBody = buf;
            },
        }),
    );
    app.use(
        bodyParser.json({
            limit: '64kb',
            verify: (req: any, _res, buf) => {
                req.rawBody = buf;
            },
        }),
    );
    app.use(
        bodyParser.urlencoded({
            extended: false,
            limit: '16kb',
            verify: (req: any, _res, buf) => {
                req.rawBody = buf;
            },
        }),
    );

    const allowNonJsonPrefixes = ['/trading/upload', '/analyze-news'];

    app.use((req, res, next) => {
        const m = req.method;
        const hasBody = Number(req.headers['content-length'] || 0) > 0;
        const isNonJsonAllowed =
            allowNonJsonPrefixes.some((prefix) =>
                req.path?.startsWith(prefix),
            ) && req.is?.('multipart/form-data');

        if (
            m === 'POST' ||
            m === 'PUT' ||
            m === 'PATCH' ||
            (m === 'DELETE' && hasBody)
        ) {
            if (
                hasBody &&
                (!req.is || (!req.is('application/json') && !isNonJsonAllowed))
            ) {
                return res
                    .status(415)
                    .json({ message: 'Unsupported Media Type' });
            }
        }
        next();
    });

    // Global validation
    app.useGlobalPipes(
        new ValidationPipe({
            whitelist: true,
            forbidNonWhitelisted: true,
            transform: true,
            transformOptions: { enableImplicitConversion: true },
            validationError: { target: false, value: false },
            // 👇 this is the new part
            disableErrorMessages: isProd,
        }),
    );

    // Security / hardening
    app.use(
        helmet({
            // you can later replace this with a real CSP in prod if you want
            contentSecurityPolicy: false,
            crossOriginEmbedderPolicy: false,
        }),
    );

    app.use(hpp());
    app.use(compression({ threshold: '1kb' }));
    app.use(cookieParser());

    // ✅ Global required headers (placed AFTER parsers, BEFORE everything else)
    app.use(new RequiredHeadersMiddleware().use);

    app.disable('x-powered-by');
    app.set('etag', 'strong');

    app.enableShutdownHooks();

    // ---- Redis health ping (non-fatal) ----
    try {
        const redis = app.get<Redis>(REDIS);
        if (redis.status === 'ready') {
            const pong = await redis.ping();
            logger.log(
                `✅ Redis connected: ${pong} (URL=${process.env.REDIS_URL || 'redis://localhost:6379'})`,
            );
        } else {
            logger.warn(
                `Redis not ready at startup (status=${redis.status}). Continuing without Redis health ping.`,
            );
        }
    } catch (e: any) {
        logger.error(`❌ Redis connection failed: ${e?.message || e}`);
    }

    const port = Number(process.env.PORT) || config.get<number>('PORT', 4000);
    await app.listen(port);
    logger.log(`🚀 Application listening on port ${port}`);
}

bootstrap();

