import { Injectable, InternalServerErrorException } from '@nestjs/common';
import { ConfigService } from '@nestjs/config';
import { SignJWT, importJWK, JWK, exportJWK } from 'jose';
import { randomUUID } from 'crypto';

type PublicJwk = {
    kty?: string;
    crv?: string;
    x?: string;
    y?: string;
    kid?: string;
    alg?: string;
    use?: string;
};

@Injectable()
export class JoseService {
    private signingKid?: string;
    private privateJwk?: JWK;
    private publicJwks: PublicJwk[] = [];
    private ready?: Promise<void>;

    constructor(private readonly cfg: ConfigService) {}

    /** Load keys only once */
    private async init() {
        if (this.ready) return this.ready;

        this.ready = (async () => {
            const kid = this.cfg.get<string>('SIGNING_KID');
            const priv = this.cfg.get<string>('SIGNING_PRIVATE_JWK');

            if (!kid || !priv) {
                throw new InternalServerErrorException(
                    'Missing SIGNING_KID or SIGNING_PRIVATE_JWK',
                );
            }

            this.signingKid = kid;
            this.privateJwk = JSON.parse(priv) as JWK;

            const pubEnv = this.cfg.get<string>('PUBLIC_JWKS');
            if (pubEnv && pubEnv.trim().length > 0) {
                this.publicJwks = JSON.parse(pubEnv);
            } else {
                // Derive public portion manually to avoid extractable restrictions
                const { kty, crv, x, y } = this.privateJwk as any;
                if (!kty || !x || !y) {
                    throw new InternalServerErrorException(
                        'Invalid SIGNING_PRIVATE_JWK: missing public components',
                    );
                }
                this.publicJwks = [
                    {
                        kty,
                        crv,
                        x,
                        y,
                        kid,
                        alg: 'ES256',
                        use: 'sig',
                    },
                ];
            }
        })();

        return this.ready;
    }

    /** Sign a JWT/JWS token for EA */
    async signToken(payload: Record<string, any>) {
        await this.init();

        const privateKey = await importJWK(this.privateJwk!, 'ES256', {
            extractable: true,
        });
        const ttlDays = Number(this.cfg.get('TOKEN_TTL_DAYS') || 30);
        const now = Math.floor(Date.now() / 1000);
        const exp = now + ttlDays * 24 * 3600;
        const issuer = this.cfg.get<string>('ISSUER') || 'license-service';

        const token = await new SignJWT(payload)
            .setProtectedHeader({ alg: 'ES256', kid: this.signingKid! })
            .setIssuedAt(now)
            .setNotBefore(now)
            .setExpirationTime(exp)
            .setIssuer(issuer)
            .setJti(randomUUID())
            .sign(privateKey);

        return { token, exp };
    }

    /** JWKS endpoint for EA (public key) */
    jwks() {
        return { keys: this.publicJwks };
    }
}

import {
    BadRequestException,
    ConflictException,
    Injectable,
    Logger,
    NotFoundException,
} from '@nestjs/common';
import { InjectModel } from '@nestjs/mongoose';
import { FilterQuery, Model, Types } from 'mongoose';
import * as membershipsSchema from './memberships.schema';
import { KolsJoinMembershipDto } from './dto/kols-join-membership.dto';
import { normalizeAccounts } from './memberships.helper';
import { Referral, ReferralDocument } from './referral.schema';

@Injectable()
export class KolsMembershipService {
    private readonly logger = new Logger(KolsMembershipService.name);

    constructor(
        @InjectModel(membershipsSchema.Membership.name)
        private readonly membershipModel: membershipsSchema.MembershipPaginateModel,
        @InjectModel(Referral.name)
        private readonly referralModel: Model<ReferralDocument>,
    ) {}

    async findByUserId(userId: string) {
        if (!Types.ObjectId.isValid(userId)) {
            throw new BadRequestException('INVALID_USER');
        }

        return this.membershipModel
            .findOne({ user: new Types.ObjectId(userId) })
            .lean()
            .exec();
    }

    async requestJoin(dto: KolsJoinMembershipDto) {
        // normalize email
        const emailRaw = dto.email;
        const email =
            typeof emailRaw === 'string'
                ? emailRaw.trim().toLowerCase()
                : undefined;
        if (!email) throw new BadRequestException('EMAIL_REQUIRED');

        // normalize accounts as string[] (up to 10), then map to MembershipAccount[]
        const accountStrings = normalizeAccounts(dto.accounts);
        const accounts =
            (accountStrings ?? []).map((acc) => ({
                account: acc,
                isVerified: false,
            })) ?? [];

        // Uniqueness: one per user OR one per email
        const ors: FilterQuery<membershipsSchema.MembershipDocument>[] = [
            { email },
        ];

        const existing = await this.membershipModel
            .findOne({ $or: ors })
            .lean();
        if (existing) {
            throw new ConflictException(
                'A membership for this user or email already exists.',
            );
        }

        const referralId = dto.referral
            ? Types.ObjectId.isValid(dto.referral)
                ? new Types.ObjectId(dto.referral)
                : null
            : undefined;
        if (dto.referral && !referralId) {
            throw new BadRequestException('INVALID_REFERRAL');
        }
        if (referralId) {
            const referralExists = await this.referralModel
                .exists({ _id: referralId })
                .exec();
            if (!referralExists)
                throw new NotFoundException('REFERRAL_NOT_FOUND');
        }

        try {
            const created = await this.membershipModel.create({
                user: new Types.ObjectId(),
                email,
                accounts,
                notes: dto.notes,
                status: membershipsSchema.MembershipStatus.Request,
                referral: referralId ?? undefined,
            });

            return { userId: created.user?.toString?.() ?? created.user };
        } catch (err: any) {
            if (err?.code === 11000) {
                throw new ConflictException(
                    'A membership for this user or email already exists.',
                );
            }
            throw err;
        }
    }
}

