import { Prop, Schema, SchemaFactory } from '@nestjs/mongoose';
import { Document, Types } from 'mongoose';

export type MembershipIpBlacklistDocument = MembershipIpBlacklist & Document;

@Schema({ collection: 'membership_ip_blacklist', timestamps: true })
export class MembershipIpBlacklist {
    @Prop({
        type: String,
        required: true,
        trim: true,
        match: [
            /^(?:\d{1,3}\.){3}\d{1,3}$|^[0-9a-fA-F:]+$/,
            'Invalid IP address',
        ],
        index: true,
    })
    ip!: string;

    @Prop({ type: String, trim: true, maxlength: 500 })
    reason?: string;
}

export const MembershipIpBlacklistSchema = SchemaFactory.createForClass(
    MembershipIpBlacklist,
);
MembershipIpBlacklistSchema.index({ ip: 1 }, { unique: true });

// src/memberships/memberships.controller.ts
import {
    Body,
    Controller,
    Get,
    HttpCode,
    HttpStatus,
    NotFoundException,
    ForbiddenException,
    Param,
    Patch,
    Post,
    Query,
    Req,
    UnauthorizedException,
} from '@nestjs/common';
import type { AuthRequest } from 'src/common/types/auth-request.type';
import type { ApiSuccess } from 'src/common/types/api-response.type';
import { MembershipsService } from './memberships.service';
import { JoinMembershipDto } from './dto/join-membership.dto';
import { MembershipDocument } from './memberships.schema';
import { PaginateMembershipsDto } from './dto/paginate-memberships.dto';
import { Throttle } from '@nestjs/throttler';
import { UpdateMembershipAdminDto } from './dto/update-membership-admin.dto';
import { Roles } from 'src/auth/decorators/roles.decorator';
import { Role } from 'src/user/user.enum';
import { ActivateLicenseDto } from './dto/activate-license.dto';
import { Public } from 'src/auth/guard/public.decorator';

interface ActivationResponseData {
    status: string;
    token: string;
}

@Controller('memberships')
export class MembershipsController {
    constructor(private readonly memberships: MembershipsService) {}

    @Get()
    @Roles(Role.Admin)
    @Throttle({ default: { limit: 30, ttl: 60_000 } })
    @HttpCode(HttpStatus.OK)
    async list(@Query() q: PaginateMembershipsDto) {
        return this.memberships.paginate(q);
    }

    @Get('user/:userId')
    @Roles(Role.Admin)
    @HttpCode(HttpStatus.OK)
    async getByUserId(
        @Param('userId') userId: string,
        @Req() req: AuthRequest,
    ): Promise<ApiSuccess<MembershipDocument>> {
        const membership = await this.memberships.findByUserId(userId);
        if (!membership) {
            throw new NotFoundException('MEMBERSHIP_NOT_FOUND');
        }

        return {
            success: true,
            statusCode: HttpStatus.OK,
            code: 'MEMBERSHIP',
            message: 'Membership fetched',
            data: membership,
            timestamp: new Date().toISOString(),
            path: req.url,
        };
    }

    @Post('request')
    @HttpCode(HttpStatus.CREATED)
    async request(
        @Body() dto: JoinMembershipDto,
        @Req() req: AuthRequest,
    ): Promise<ApiSuccess> {
        const userId = req.user?.userId;
        await this.memberships.requestJoin(dto, userId);

        return {
            success: true,
            statusCode: HttpStatus.CREATED,
            code: 'MEMBERSHIP_REQUESTED',
            message: 'Membership request submitted',
            timestamp: new Date().toISOString(),
            path: req.url,
        };
    }

    @Get('me')
    @HttpCode(HttpStatus.OK)
    async getMine(@Req() req: AuthRequest) {
        const userId = req.user?.userId;
        if (!userId) throw new UnauthorizedException('AUTH_REQUIRED');

        const membership = await this.memberships.findByUserId(userId);

        if (!membership) throw new NotFoundException('MEMBERSHIP_NOT_FOUND');

        return {
            success: true,
            statusCode: HttpStatus.OK,
            code: 'MEMBERSHIP',
            message: 'Membership fetched',
            data: membership,
            timestamp: new Date().toISOString(),
            path: req.url,
        };
    }

    @Post('appeal')
    @HttpCode(HttpStatus.OK)
    async appeal(
        @Body() dto: JoinMembershipDto,
        @Req() req: AuthRequest,
    ): Promise<ApiSuccess> {
        const userId = req.user?.userId;
        if (!userId) throw new UnauthorizedException('AUTH_REQUIRED');

        await this.memberships.appeal(userId, dto);

        return {
            success: true,
            statusCode: HttpStatus.OK,
            code: 'MEMBERSHIP_APPEALED',
            message: 'Membership appeal submitted',
            timestamp: new Date().toISOString(),
            path: req.url,
        };
    }

    @Patch(':id/admin')
    @Roles(Role.Admin)
    @HttpCode(HttpStatus.OK)
    async adminUpdate(
        @Param('id') id: string,
        @Body() dto: UpdateMembershipAdminDto,
        @Req() req: AuthRequest,
    ): Promise<ApiSuccess> {
        await this.memberships.updateAdmin(id, dto, req.user?.userId);
        return {
            success: true,
            statusCode: HttpStatus.OK,
            code: 'MEMBERSHIP_UPDATED',
            message: 'Membership updated',
            timestamp: new Date().toISOString(),
            path: req.url,
        };
    }

    @Post(':id/license')
    @Roles(Role.Admin)
    @Throttle({ default: { limit: 10, ttl: 60_000 } }) // ✅ Rate limit
    @HttpCode(HttpStatus.CREATED)
    async createLicense(
        @Param('id') id: string,
        @Req() req: AuthRequest,
    ): Promise<ApiSuccess<MembershipDocument>> {
        const membership = await this.memberships.createLicenseKeyForMembership(
            id,
            req.user?.userId,
        );
        return {
            success: true,
            statusCode: HttpStatus.CREATED,
            code: 'LICENSE_CREATED',
            message: 'License key generated successfully',
            timestamp: new Date().toISOString(),
            path: req.url,
        };
    }

    @Post('activate')
    @Public()
    @HttpCode(HttpStatus.OK)
    async activate(
        @Body() dto: ActivateLicenseDto,
        @Req() req: AuthRequest,
    ): Promise<ApiSuccess<ActivationResponseData>> {
        const xffHeader = req.headers['x-forwarded-for'];
        if (!xffHeader) {
            throw new ForbiddenException('X_FORWARDED_FOR_REQUIRED');
        }
        const xff = Array.isArray(xffHeader) ? xffHeader[0] : xffHeader;
        const ua = req.headers['user-agent'];
        const ip =
            typeof xff === 'string' && xff.trim()
                ? xff.split(',')[0].trim()
                : req.ip;
        const result = await this.memberships.activate(
            dto,
            ip,
            ua ?? undefined,
        );

        return {
            success: true,
            statusCode: HttpStatus.OK,
            code: 'LICENSE_ACTIVATED',
            message: 'License activated successfully',
            data: {
                status: 'OK',
                token: result.token,
            },
            timestamp: new Date().toISOString(),
            path: '/memberships/activate',
        };
    }

    @Post('activate/free')
    @Public()
    @HttpCode(HttpStatus.OK)
    async activateFree(
        @Body() dto: ActivateLicenseDto,
        @Req() req: AuthRequest,
    ): Promise<ApiSuccess<ActivationResponseData>> {
        const xffHeader = req.headers['x-forwarded-for'];
        if (!xffHeader) {
            throw new ForbiddenException('X_FORWARDED_FOR_REQUIRED');
        }
        const xff = Array.isArray(xffHeader) ? xffHeader[0] : xffHeader;
        const ua = req.headers['user-agent'];
        const ip =
            typeof xff === 'string' && xff.trim()
                ? xff.split(',')[0].trim()
                : req.ip;
        const result = await this.memberships.activateFreeLicense(
            dto,
            ip,
            ua ?? undefined,
        );
        return {
            success: true,
            statusCode: HttpStatus.OK,
            code: 'LICENSE_ACTIVATED',
            message: 'Free license activated successfully',
            data: {
                status: 'OK',
                token: result.token,
            },
            timestamp: new Date().toISOString(),
            path: '/memberships/activate/free',
        };
    }
}

// memberships.service.ts
import {
    BadRequestException,
    ConflictException,
    ForbiddenException,
    Injectable,
    Logger,
    NotFoundException,
} from '@nestjs/common';
import { InjectModel } from '@nestjs/mongoose';
import {
    FilterQuery,
    Model,
    PaginateOptions,
    PaginateResult,
    Types,
} from 'mongoose';
import * as membershipsSchema from './memberships.schema';
import { JoinMembershipDto } from './dto/join-membership.dto';
import { User, UserDocument } from 'src/user/user.schema';
import { PaginateMembershipsDto } from './dto/paginate-memberships.dto';
import { UpdateMembershipAdminDto } from './dto/update-membership-admin.dto';
import { buildAdminTinyPayload, normalizeAccounts } from './memberships.helper';
import { WebPushSubService } from 'src/web-push-sub/web-push-sub.service';
import { randomBytes } from 'crypto';
import { ActivateLicenseDto } from './dto/activate-license.dto';
import { JoseService } from './jose.service';
import {
    MembershipAccountType,
    MembershipDocument,
} from './memberships.schema';
import { Referral } from './referral.schema';
import {
    MembershipIpBlacklist,
    MembershipIpBlacklistDocument,
} from './membership-ip-blacklist.schema';
import {
    Subscription,
    SubscriptionDocument,
    SubscriptionStatus,
} from 'src/subscriptions/subscriptions.schema';
import { PublicUser } from 'src/common/types/public-user.type';

export type ReferralWithOwner = Referral & {
    owner: Pick<User, 'firstName' | 'lastName'>;
};

export type MembershipWithReferralOwner = MembershipDocument & {
    referral?: ReferralWithOwner;
};

@Injectable()
export class MembershipsService {
    private readonly logger = new Logger(MembershipsService.name);
    constructor(
        @InjectModel(membershipsSchema.Membership.name)
        private readonly membershipModel: membershipsSchema.MembershipPaginateModel,
        @InjectModel(User.name)
        private readonly userModel: Model<UserDocument>,
        @InjectModel(MembershipIpBlacklist.name)
        private readonly ipBlacklistModel: Model<MembershipIpBlacklistDocument>,
        @InjectModel(Subscription.name)
        private readonly subscriptionModel: Model<SubscriptionDocument>,
        private readonly webPushSubService: WebPushSubService,
        private readonly jose: JoseService,
    ) {}

    async findAll(): Promise<MembershipDocument[]> {
        return this.membershipModel
            .find({})
            .populate('user', '_id email firstName lastName')
            .lean()
            .exec();
    }

    async findByUserId(userId: string): Promise<MembershipDocument | null> {
        const membership = await this.membershipModel
            .findOne({ user: new Types.ObjectId(userId) })
            .populate({
                path: 'user',
                select: '_id email firstName lastName',
            })
            .populate({
                path: 'referral',
                select: '_id code link owner', // include whatever fields you need
                populate: {
                    path: 'owner',
                    select: '_id email firstName lastName',
                },
            })
            .populate({
                path: 'updatedBy',
                select: '_id email firstName lastName',
            })
            .exec();

        return membership;
    }

    async requestJoin(dto: JoinMembershipDto, currentUserId?: string) {
        if (!currentUserId) throw new BadRequestException('USER_REQUIRED');

        const user = await this.userModel.findById(currentUserId);

        // normalize email
        const emailRaw = dto.email;
        const email =
            typeof emailRaw === 'string'
                ? emailRaw.trim().toLowerCase()
                : undefined;
        if (!email) throw new BadRequestException('EMAIL_REQUIRED');

        // normalize accounts as string[] (up to 10), then map to MembershipAccount[]
        const accountStrings = normalizeAccounts(dto.accounts);
        const accounts =
            (accountStrings ?? []).map((acc) => ({
                account: acc,
                isVerified: false, // default on creation
            })) ?? [];

        // Uniqueness: one per user OR one per email
        const ors: FilterQuery<membershipsSchema.MembershipDocument>[] = [
            { user: new Types.ObjectId(currentUserId) },
            { email },
        ];

        const existing = await this.membershipModel
            .findOne({ $or: ors })
            .lean();
        if (existing) {
            throw new ConflictException(
                'A membership for this user or email already exists.',
            );
        }

        try {
            const created = await this.membershipModel.create({
                user: new Types.ObjectId(currentUserId),
                email,
                accounts, // 👈 now MembershipAccount[]
                notes: dto.notes ?? undefined,
                status: membershipsSchema.MembershipStatus.Request,
                referral: new Types.ObjectId(dto.referral) ?? undefined, // validated MongoId string (or undefined)
            });

            // Push notification (unchanged)
            try {
                const tinyPayload = {
                    title: 'New membership request',
                    body: `${user?.firstName} ${user?.lastName} just asked to join`,
                };

                let excludeId: Types.ObjectId | null = null;
                const maybeAuthorId = (dto as any)?.authorId;
                if (maybeAuthorId) {
                    try {
                        excludeId = new Types.ObjectId(String(maybeAuthorId));
                    } catch {
                        /* ignore bad id */
                    }
                }

                const recipients = await this.webPushSubService.getAdminIds();

                if (recipients.length) {
                    await this.webPushSubService.sendToUsers(
                        recipients,
                        tinyPayload,
                        3600,
                    );
                }
            } catch (e) {
                console.warn('[AnalyzeNews.create] push enqueue failed:', e);
            }

            return this.membershipModel.findById(created._id).lean();
        } catch (err: any) {
            if (err?.code === 11000) {
                throw new ConflictException(
                    'A membership for this user or email already exists.',
                );
            }
            throw err;
        }
    }

    async appeal(userId: string, dto: JoinMembershipDto) {
        const membership = await this.membershipModel
            .findOne({ user: new Types.ObjectId(userId) })
            .populate('user')
            .exec();

        if (!membership) throw new NotFoundException('MEMBERSHIP_NOT_FOUND');

        if (
            membership.status !== membershipsSchema.MembershipStatus.Rejected &&
            membership.status !== membershipsSchema.MembershipStatus.Ended &&
            membership.status !== membershipsSchema.MembershipStatus.Verified
        ) {
            throw new ForbiddenException('APPEAL_NOT_ALLOWED');
        }

        // normalize incoming fields
        const emailProvided = Object.prototype.hasOwnProperty.call(
            dto,
            'email',
        );
        const email =
            typeof dto.email === 'string'
                ? dto.email.trim().toLowerCase()
                : undefined;

        const accountsProvided = Object.prototype.hasOwnProperty.call(
            dto,
            'accounts',
        );

        // 🔹 normalize accounts only if provided
        const accountStrings = accountsProvided
            ? normalizeAccounts(dto.accounts)
            : undefined;

        const referralProvided = Object.prototype.hasOwnProperty.call(
            dto,
            'referral',
        );
        const referral = dto.referral; // validated MongoId string or undefined

        // If email is provided, validate
        if (emailProvided) {
            if (!email) {
                // email is required by schema; don't allow clearing it
                throw new BadRequestException('EMAIL_REQUIRED');
            }
            const dup = await this.membershipModel
                .findOne({ email, _id: { $ne: membership._id } })
                .lean()
                .exec();
            if (dup) {
                throw new ConflictException(
                    'A membership with this email already exists.',
                );
            }
            membership.email = email;
        }

        if (accountsProvided) {
            // 🔹 enforce at least one account if user is trying to change them
            if (!accountStrings || accountStrings.length === 0) {
                throw new BadRequestException('AT_LEAST_ONE_ACCOUNT_REQUIRED');
            }

            // 🔹 map existing accounts by account string
            const existingByAccount = new Map<string, MembershipAccountType>(
                (membership.accounts ?? []).map((acc) => [acc.account, acc]),
            );

            const nextAccounts: MembershipAccountType[] = [];

            for (const acc of accountStrings) {
                const existing = existingByAccount.get(acc);

                if (existing) {
                    // ✅ keep admin’s isVerified value and existing _id
                    nextAccounts.push(existing);
                } else {
                    // ✅ new account: default isVerified = false
                    nextAccounts.push({
                        account: acc,
                        isVerified: false,
                    } as MembershipAccountType);
                }
            }

            // 🔹 replace membership.accounts with merged list
            membership.accounts = nextAccounts;
        }

        // ✅ Allow updating referral on appeal
        if (referralProvided) {
            if (referral) {
                membership.referral = referral as any; // Mongoose will cast string -> ObjectId
            } else {
                membership.referral = undefined;
            }
        }

        if (Object.prototype.hasOwnProperty.call(dto, 'notes')) {
            membership.notes = dto.notes?.trim() || undefined;
        }

        // Reset status/admin note for re-review
        membership.status = membershipsSchema.MembershipStatus.Request;
        membership.adminNotes = undefined;

        try {
            try {
                const tinyPayload = {
                    title: 'Appeal membership request',
                    body: `${membership?.user?.firstName} ${membership?.user?.lastName} just asked to Appeal`,
                };

                let excludeId: Types.ObjectId | null = null;
                const maybeAuthorId = (dto as any)?.authorId;

                if (maybeAuthorId) {
                    try {
                        excludeId = new Types.ObjectId(String(maybeAuthorId));
                    } catch {
                        /* ignore bad id */
                    }
                }

                const recipients = await this.webPushSubService.getAdminIds();

                if (recipients.length) {
                    await this.webPushSubService.sendToUsers(
                        recipients,
                        tinyPayload,
                        3600,
                    );
                }
            } catch (e) {
                console.warn('[AnalyzeNews.create] push enqueue failed:', e);
            }

            await membership.save();

            return this.membershipModel.findById(membership._id).lean().exec();
        } catch (err: any) {
            if (err?.code === 11000) {
                throw new ConflictException(
                    'A membership with this email already exists.',
                );
            }
            throw err;
        }
    }

    async paginate(
        query: PaginateMembershipsDto,
    ): Promise<PaginateResult<MembershipDocument>> {
        const { q, status, referral, page = 1, limit = 20 } = query;

        const filter: FilterQuery<MembershipDocument> = {};
        const or: FilterQuery<MembershipDocument>[] = [];

        if (q && q.trim()) {
            const rx = new RegExp(this.escapeRegex(q.trim()), 'i');

            // membership email
            or.push({ email: rx });

            // related user search
            const users = await this.userModel
                .find(
                    {
                        $or: [
                            { firstName: rx },
                            { lastName: rx },
                            { email: rx },
                        ],
                    },
                    { _id: 1 },
                )
                .limit(1000)
                .lean()
                .exec();

            const userIds = users.map((u) => u._id);
            if (userIds.length) {
                or.push({ user: { $in: userIds } });
            }
        }

        if (or.length) {
            filter.$or = or;
        }

        if (status) {
            filter.status = status;
        }

        if (referral) {
            filter.referral = new Types.ObjectId(referral);
        }

        const options: PaginateOptions = {
            page: Number(page) || 1,
            limit: Number(limit) || 20,
            sort: { createdAt: -1 },
            lean: true,
            leanWithId: false,
            populate: [
                { path: 'user', select: '_id email firstName lastName' },
                {
                    path: 'referral',
                    select: '_id code link owner',
                    populate: {
                        path: 'owner',
                        select: '_id email firstName lastName',
                    },
                },
            ],
        };

        return this.membershipModel.paginate(filter, options);
    }

    private escapeRegex(s: string) {
        return s.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    }

    async updateAdmin(
        id: string,
        dto: UpdateMembershipAdminDto,
        updatedBy?: string,
    ) {
        if (!Types.ObjectId.isValid(id)) {
            throw new BadRequestException('INVALID_ID');
        }

        const membership = await this.membershipModel.findById(id).exec();
        if (!membership) throw new NotFoundException('MEMBERSHIP_NOT_FOUND');

        // apply changes only if present
        if (dto.status !== undefined) {
            membership.status = dto.status;
        }

        if (dto.adminNotes !== undefined) {
            membership.adminNotes = dto.adminNotes?.trim() || undefined;
        }

        // 👇 handle accounts from DTO
        if (dto.accounts !== undefined) {
            // if you want to *replace* all accounts:
            membership.accounts = (dto.accounts || [])
                // optional: drop entries without a valid account string
                .filter((a) => a && a.account && a.account.trim().length > 0)
                .map((a) => ({
                    account: a.account.trim(),
                    isVerified: a.isVerified ?? false,
                }));
        }

        if (updatedBy && Types.ObjectId.isValid(updatedBy)) {
            membership.updatedBy = new Types.ObjectId(updatedBy);
        }

        try {
            const tinyPayload = buildAdminTinyPayload(membership, dto, {
                maxReasonLength: 160,
            });
            const userId = membership?.user || '';
            const recipients = [new Types.ObjectId(userId?.toString())];

            if (recipients.length) {
                await this.webPushSubService.sendToUsers(
                    recipients,
                    tinyPayload,
                    3600,
                );
            }
        } catch (e) {
            console.warn('[Membership.updateAdmin] push enqueue failed:', e);
        }

        await membership.save();
        return this.membershipModel.findById(membership._id).lean().exec();
    }

    private generateLicenseKey(
        membership: membershipsSchema.MembershipDocument,
    ): string {
        // Prefix can be anything: product ID, "EA", etc.
        const prefix = 'EA';
        const randomPart = randomBytes(6).toString('base64url').toUpperCase(); // short but random
        // You can also mix in part of email or user id if you want
        return `${prefix}-${randomPart}`;
    }

    async createLicenseKeyForMembership(id: string, updatedBy?: string) {
        if (!Types.ObjectId.isValid(id)) {
            throw new BadRequestException('INVALID_ID');
        }

        const membership = await this.membershipModel.findById(id).exec();
        if (!membership) {
            throw new NotFoundException('MEMBERSHIP_NOT_FOUND');
        }

        if (membership.licenseKey) {
            // already has a key, don't overwrite silently
            throw new ConflictException('LICENSE_ALREADY_EXISTS');
        }

        const key = this.generateLicenseKey(membership);
        membership.licenseKey = key;

        if (updatedBy && Types.ObjectId.isValid(updatedBy)) {
            membership.updatedBy = new Types.ObjectId(updatedBy);
        }

        await membership.save();

        try {
            const userId = membership.user;

            if (userId) {
                const recipientId = new Types.ObjectId(userId.toString());
                const tinyPayload = {
                    title: 'License key created',
                    body: 'Your EA license key has been generated and is now active.',
                };

                const recipients = [recipientId];

                await this.webPushSubService.sendToUsers(
                    recipients,
                    tinyPayload,
                    3600,
                );
            }
        } catch (e) {
            this.logger.warn(
                '[Memberships.createLicenseKeyForMembership] push enqueue failed:',
                e,
            );
        }
        // Return a lean object with the new licenseKey
        return this.membershipModel.findById(membership._id).lean().exec();
    }

    // -------- ACTIVATION FOR MT5 EA --------
    private deny(
        reason: string,
        context?: {
            maskedKey?: string;
            accountLogin?: string | number;
            ip?: string;
            ua?: string;
            membershipId?: string;
        },
    ): never {
        this.logger.warn(
            `Activation denied: ${reason} | key=${context?.maskedKey ?? 'N/A'} | account=${context?.accountLogin ?? 'N/A'} | ip=${context?.ip ?? 'N/A'}`,
        );
        throw new ForbiddenException({ status: 'INVALID', reason });
    }

    async activate(dto: ActivateLicenseDto, ip?: string, ua?: string) {
        return this.performActivation(dto, ip, ua, {
            requireSubscription: true,
        });
    }

    async activateFreeLicense(
        dto: ActivateLicenseDto,
        ip?: string,
        ua?: string,
    ) {
        // Same activation flow as activate but skips subscription checks for free licenses
        return this.performActivation(dto, ip, ua, {
            requireSubscription: false,
        });
    }

    private async performActivation(
        dto: ActivateLicenseDto,
        ip?: string,
        ua?: string,
        options?: { requireSubscription?: boolean },
    ) {
        const { requireSubscription = true } = options ?? {};
        const key = dto.key?.trim();
        const accountLogin = String(dto.accountLogin ?? '').trim();
        const maskedKey = key ? `${key.slice(0, 4)}***` : undefined; // don't log full key
        // Initial attempt log
        this.logger.log(
            `Activation attempt | key=${maskedKey ?? 'N/A'} | account=${accountLogin || 'N/A'} | ip=${ip ?? 'N/A'}`,
        );

        // Slow down known abusive IPs
        // if (ip) {
        //     const blacklisted = await this.ipBlacklistModel.findOne({ ip }).lean().exec();
        //     if (blacklisted) {
        //         this.logger.warn(`[Memberships.activate] throttling blacklisted IP ${ip}`);
        //         await this.delayMs(5 * 60 * 1000);
        //     }
        // }

        if (!key) {
            this.deny('key_required', { maskedKey, accountLogin, ip, ua });
        }

        if (!accountLogin) {
            this.deny('account_required', { maskedKey, accountLogin, ip, ua });
        }

        const membership = await this.membershipModel
            .findOne({ licenseKey: key })
            .populate('user', '_id email firstName lastName')
            .exec();

        if (!membership) {
            this.deny('not_found', { maskedKey, accountLogin, ip, ua });
        }

        if (requireSubscription) {
            await this.ensureLicenseRequiredSubscription(
                membership?.user as unknown as PublicUser,
                {
                    maskedKey,
                    accountLogin,
                    ip,
                    ua,
                    membershipId: String(membership._id),
                },
            );
        }

        if (membership.status !== membershipsSchema.MembershipStatus.Verified) {
            this.deny('membership_not_verified', {
                maskedKey,
                accountLogin,
                ip,
                ua,
                membershipId: String(membership._id),
            });
        }
        // 🔍 Require account in membership.accounts with isVerified = true
        const accounts = Array.isArray(membership.accounts)
            ? membership.accounts
            : [];

        const accountDoc = accounts.find(
            (a) => a.account === accountLogin && a.isVerified,
        );

        if (!accountDoc) {
            this.deny('account_not_verified', {
                maskedKey,
                accountLogin,
                ip,
                ua,
                membershipId: String(membership._id),
            });
        }

        // 👉 Persist caller IP (x-forwarded-for) when available
        if (ip) {
            membership.xForwardedFor = ip;
            await membership.save();
        }

        // Build token payload
        const membershipId = (membership._id as Types.ObjectId).toHexString();
        const userId = (membership.user as any)?._id?.toString?.();

        const payload = {
            sub: `membership:${membershipId}`,
            membershipId,
            licenseKey: membership.licenseKey,
            accountLogin,
            email: membership.email,
            userId,
            ip,
            ua,
        };

        const { token } = await this.jose.signToken(payload);

        // Success log
        this.logger.log(
            `Activation success | membershipId=${membershipId} | userId=${userId ?? 'N/A'} | account=${accountLogin} | ip=${ip ?? 'N/A'}`,
        );

        // Fire-and-forget push notification via BullMQ
        try {
            if (userId) {
                const tinyPayload = {
                    title: 'License activated',
                    body: `Your EA license was activated for account ${accountLogin}.`,
                };

                await this.webPushSubService.sendToUsers(
                    [new Types.ObjectId(userId)],
                    tinyPayload,
                    3600,
                );
            }
        } catch (e) {
            this.logger.warn('[Memberships.activate] push enqueue failed:', e);
        }

        // 🔥 RETURN EA-SAFE JSON
        return {
            status: 'OK',
            token,
        };
    }

    private async ensureLicenseRequiredSubscription(
        userId: PublicUser,
        ctx: Record<string, any>,
    ) {
        const subscription = await this.subscriptionModel
            .find({
                user: userId?._id,
                status: SubscriptionStatus.Active,
            })
            .populate('product');

        if (!subscription) {
            this.deny('subscription_not_active', ctx);
        }

        const checkIsRequiresLicenseKey = subscription.find(
            (sub) => sub?.product?.requiresLicenseKey === true,
        );
        if (!checkIsRequiresLicenseKey) {
            this.deny('product_not_license', ctx);
        }

        this.logger.log(`[Memberships.activate] license subscription ok`);
    }
}

// src/referrals/referrals.service.ts
import {
    BadRequestException,
    ConflictException,
    ForbiddenException,
    Injectable,
    NotFoundException,
} from '@nestjs/common';
import { InjectModel } from '@nestjs/mongoose';
import { FilterQuery, Model, PaginateOptions, Types } from 'mongoose';

import { Referral } from './referral.schema';
import type {
    ReferralDocument,
    ReferralPaginateModel,
} from './referral.schema';
import { User, UserDocument } from 'src/user/user.schema';
import { Role } from 'src/user/user.enum';

type CreateReferralInput = {
    ownerId: string;
    link: string;
    code: string;
};

type UpdateReferralInput = {
    ownerId?: string;
    link?: string;
    code?: string;
};

type PaginateReferralsInput = {
    page?: number;
    limit?: number;
    search?: string; // search by user firstName / lastName (case-insensitive)
};

@Injectable()
export class ReferralsService {
    constructor(
        @InjectModel(Referral.name)
        private readonly referralModel: ReferralPaginateModel,

        @InjectModel(User.name)
        private readonly userModel: Model<UserDocument>,
    ) {}

    // --- Helpers --------------------------------------------------------------

    private ensureAdmin(role?: Role) {
        if (role !== Role.Admin) {
            throw new ForbiddenException('ADMIN_ONLY');
        }
    }

    private normalizeCode(raw?: string): string | undefined {
        if (typeof raw !== 'string') return undefined;
        const v = raw.trim().toUpperCase();
        return v.length ? v : undefined;
    }

    private normalizeLink(raw?: string): string | undefined {
        if (typeof raw !== 'string') return undefined;
        const v = raw.trim();
        return v.length ? v : undefined;
    }

    private toObjectId(id: string, field: string): Types.ObjectId {
        if (!Types.ObjectId.isValid(id)) {
            throw new BadRequestException(`INVALID_${field.toUpperCase()}`);
        }
        return new Types.ObjectId(id);
    }

    // --- Create (admin only) --------------------------------------------------

    async createReferral(
        dto: CreateReferralInput,
        currentUserRole?: Role,
    ): Promise<ReferralDocument> {
        this.ensureAdmin(currentUserRole);

        const ownerId = this.toObjectId(dto.ownerId, 'owner_id');

        // make sure owner exists
        const ownerExists = await this.userModel
            .exists({ _id: ownerId })
            .exec();
        if (!ownerExists) {
            throw new NotFoundException('OWNER_NOT_FOUND');
        }

        const code = this.normalizeCode(dto.code);
        if (!code) throw new BadRequestException('CODE_REQUIRED');

        const link = this.normalizeLink(dto.link);
        if (!link) throw new BadRequestException('LINK_REQUIRED');

        try {
            const doc = await this.referralModel.create({
                owner: ownerId,
                link,
                code,
            });
            return doc;
        } catch (err: any) {
            if (err?.code === 11000) {
                // duplicate key (code or link)
                throw new ConflictException('REFERRAL_DUPLICATE');
            }
            throw err;
        }
    }

    // --- Update (admin only) --------------------------------------------------

    async updateReferralById(id: string, dto: UpdateReferralInput) {
        const _id = this.toObjectId(id, 'id');

        const doc = await this.referralModel.findById(_id).exec();
        if (!doc) {
            throw new NotFoundException('REFERRAL_NOT_FOUND');
        }

        if (dto.ownerId) {
            const ownerId = this.toObjectId(dto.ownerId, 'owner_id');
            const ownerExists = await this.userModel
                .exists({ _id: ownerId })
                .exec();
            if (!ownerExists) {
                throw new NotFoundException('OWNER_NOT_FOUND');
            }
            doc.owner = ownerId;
        }

        if (dto.link !== undefined) {
            const link = this.normalizeLink(dto.link);
            if (!link) throw new BadRequestException('LINK_REQUIRED');
            doc.link = link;
        }

        if (dto.code !== undefined) {
            const code = this.normalizeCode(dto.code);
            if (!code) throw new BadRequestException('CODE_REQUIRED');
            doc.code = code;
        }

        try {
            await doc.save();
            return this.referralModel
                .findById(doc._id)
                .populate({
                    path: 'owner',
                    select: '_id firstName lastName email',
                })
                .lean()
                .exec();
        } catch (err: any) {
            if (err?.code === 11000) {
                throw new ConflictException('REFERRAL_DUPLICATE');
            }
            throw err;
        }
    }

    // --- Delete (admin only) --------------------------------------------------

    async deleteReferralById(id: string, currentUserRole?: Role) {
        this.ensureAdmin(currentUserRole);

        const _id = this.toObjectId(id, 'id');

        const deleted = await this.referralModel
            .findByIdAndDelete(_id)
            .lean()
            .exec();
        if (!deleted) {
            throw new NotFoundException('REFERRAL_NOT_FOUND');
        }

        return deleted;
    }

    // --- Get one by owner -----------------------------------------------------

    async getByOwner(ownerId: string) {
        const _ownerId = this.toObjectId(ownerId, 'owner_id');

        const doc = await this.referralModel
            .findOne({ owner: _ownerId })
            .sort({ createdAt: -1 }) // latest if multiple
            .populate({ path: 'owner', select: '_id firstName lastName email' })
            .lean()
            .exec();

        if (!doc) {
            throw new NotFoundException('REFERRAL_NOT_FOUND');
        }

        return doc;
    }

    // --- Get all + search by user name ---------------------------------------

    async paginate(q: PaginateReferralsInput) {
        const page = q.page && q.page > 0 ? q.page : 1;
        const limit = q.limit && q.limit > 0 ? q.limit : 20;

        const filter: FilterQuery<ReferralDocument> = {};

        // search by user's firstName / lastName
        if (q.search && q.search.trim()) {
            const search = q.search.trim();
            const regex = new RegExp(search, 'i');

            const users = await this.userModel
                .find(
                    {
                        $or: [{ firstName: regex }, { lastName: regex }],
                    },
                    { _id: 1 },
                )
                .lean()
                .exec();

            const ownerIds = users.map((u) => u._id);

            if (!ownerIds.length) {
                // No matching users → return empty paginated response
                return {
                    items: [],
                    total: 0,
                    page,
                    limit,
                    totalPages: 0,
                    hasNext: false,
                    hasPrev: false,
                };
            }

            filter.owner = { $in: ownerIds };
        }

        const options: PaginateOptions = {
            page,
            limit,
            sort: { createdAt: -1 },
            lean: true,
            populate: [
                { path: 'owner', select: '_id firstName lastName email' },
            ],
            customLabels: {
                totalDocs: 'total',
                docs: 'items',
                page: 'page',
                limit: 'limit',
                totalPages: 'totalPages',
                hasPrevPage: 'hasPrev',
                hasNextPage: 'hasNext',
            },
        };

        const res: any = await this.referralModel.paginate(filter, options);

        return {
            items: res.items,
            total: res.total,
            page: res.page,
            limit: res.limit,
            totalPages: res.totalPages,
            hasNext: res.hasNext,
            hasPrev: res.hasPrev,
        };
    }
}

// src/middleware/required-headers.middleware.ts
import {
    BadRequestException,
    Injectable,
    NestMiddleware,
} from '@nestjs/common';
import type { Request, Response, NextFunction } from 'express';
import crypto from 'crypto';

const SKIP = (req: Request) =>
    req.method === 'OPTIONS' ||
    req.url === '/health' ||
    req.url.startsWith('/_next') ||
    req.url.startsWith('/static') ||
    req.url.startsWith('/favicon.ico');

@Injectable()
export class RequiredHeadersMiddleware implements NestMiddleware {
    use(req: Request, _res: Response, next: NextFunction) {
        if (SKIP(req)) return next();

        // Ensure a request id exists (don’t reject if missing; just set it)
        if (!req.headers['x-request-id']) {
            req.headers['x-request-id'] = crypto.randomUUID();
        }

        const method = req.method;
        const mutating =
            method === 'POST' ||
            method === 'PUT' ||
            method === 'PATCH' ||
            method === 'DELETE';
        const hasCookies = Boolean((req as any).headers.cookie);

        if (mutating && hasCookies) {
            if (!req.headers['x-csrf-token'])
                throw new BadRequestException('Missing X-CSRF-Token');
        }

        return next();
    }
}

// src/order/dto/paginate-orders.dto.ts
import { Transform, Type } from 'class-transformer';
import { IsEnum, IsInt, IsOptional, IsString, Min } from 'class-validator';
import { OrderStatus } from '../order.schema';

export class PaginateOrdersDto {
    @IsOptional()
    @IsString()
    @Transform(({ value }) =>
        typeof value === 'string' ? value.trim() : value,
    )
    q?: string;

    @IsOptional()
    @IsEnum(OrderStatus)
    status?: OrderStatus;

    @Type(() => Number)
    @IsInt()
    @Min(1)
    @IsOptional()
