// src/order/dto/user-create-order.dto.ts
import {
    IsEnum,
    IsMongoId,
    IsNumber,
    IsString,
    Matches,
    MaxLength,
    MinLength,
    Min,
    IsOptional,
} from 'class-validator';
import { Transform } from 'class-transformer';
import { BillPeriod } from 'src/products/product.schema';
import { OrderStatus } from '../order.schema';

export class UserCreateOrderDto {
    @IsMongoId()
    product!: string;

    @IsEnum(BillPeriod)
    billPeriod!: BillPeriod;

    @IsNumber()
    @Min(0)
    amount!: number;

    // Bank account name (customer uppercase full name, e.g. "JOHN DOE")
    @IsString()
    @MinLength(4)
    @MaxLength(120)
    @Matches(/^[A-Z]+(?: [A-Z]+)+$/, {
        message:
            'Bank Account Name must be uppercase words separated by spaces (e.g. JOHN DOE)',
    })
    @Transform(({ value }) =>
        typeof value === 'string' ? value.trim().toUpperCase() : value,
    )
    bankAccountName!: string;

    // OPTIONAL: only validated if present
    @IsOptional()
    @IsString()
    @MinLength(2)
    @MaxLength(120)
    @Transform(({ value }) =>
        typeof value === 'string' ? value.trim() : value,
    )
    tradingViewUsername?: string;

    @IsOptional()
    @IsEnum(OrderStatus)
    status?: OrderStatus;
}

// src/order/order.controller.ts
import {
    BadRequestException,
    Controller,
    Headers,
    Post,
    Body,
    Req,
    Get,
    Query,
    Param,
    Patch,
} from '@nestjs/common';
import { Throttle } from '@nestjs/throttler';
import { Logger } from 'nestjs-pino';

import { OrderService } from './order.service';
import type { AuthRequest } from 'src/common/types/auth-request.type';
import { UserCreateOrderDto } from './dto/user-create-order.dto';
import { PaginateOrdersDto } from './dto/paginate-orders.dto';
import { UpdateOrderStatusDto } from './dto/update-order-status.dto';
import { Roles } from 'src/auth/decorators/roles.decorator';
import { Role } from 'src/user/user.enum';

@Controller('orders')
export class OrderController {
    constructor(
        private readonly orderService: OrderService,
        private readonly logger: Logger,
    ) {}

    @Post()
    @Throttle({ short: { ttl: 10_000, limit: 5 } })
    async createOrder(
        @Req() req: AuthRequest,
        @Body() dto: UserCreateOrderDto,
        @Headers('x-idempotency-key') xIdem?: string,
        @Headers('idempotency-key') idem?: string,
    ) {
        const userId = req?.user?.userId;
        if (!userId) throw new BadRequestException('AUTH_REQUIRED');

        const idempotencyKey = (xIdem || idem || '').trim() || undefined;
        if (idempotencyKey && idempotencyKey.length > 128) {
            throw new BadRequestException('Invalid idempotency key length');
        }

        this.logger.log(
            `Create order: user=${userId} reqId=${(req as any).id} idem=${idempotencyKey ?? 'none'}`,
        );

        return this.orderService.createUserRequestOrder(
            userId,
            dto,
            idempotencyKey,
        );
    }

    @Patch('id/:id/reorder')
    async reorderOrder(
        @Param('id') id: string,
        @Req() req: AuthRequest,
        @Body() dto: UserCreateOrderDto,
    ) {
        const userId = req?.user?.userId;
        if (!userId) throw new BadRequestException('AUTH_REQUIRED');
        this.logger.log(
            `Reorder: user=${userId} order=${id} reqId=${(req as any).id}`,
        );
        return this.orderService.updateUserOrder(id, userId, dto);
    }

    @Get('id/:id')
    @Roles(Role.Admin)
    async getOrderById(@Param('id') id: string) {
        return this.orderService.getOrderById(id);
    }

    @Patch('id/:id/status')
    @Roles(Role.Admin)
    async updateOrderStatus(
        @Param('id') id: string,
        @Body() dto: UpdateOrderStatusDto,
        @Req() req: AuthRequest,
    ) {
        return this.orderService.updateOrderStatus(id, dto, req?.user?.userId);
    }

    @Get()
    @Roles(Role.Admin)
    paginate(@Query() query: PaginateOrdersDto) {
        return this.orderService.paginate(query);
    }

    @Get('subscription/:subscriptionId')
    getBySubscription(@Param('subscriptionId') subscriptionId: string) {
        return this.orderService.getOrderBySubscription(subscriptionId);
    }
}

// src/marketplace/order.service.ts
import {
    Injectable,
    BadRequestException,
    NotFoundException,
} from '@nestjs/common';
import { InjectModel } from '@nestjs/mongoose';
import {
    FilterQuery,
    Model,
    PaginateOptions,
    PaginateResult,
    Types,
} from 'mongoose';
import { UserCreateOrderDto } from './dto/user-create-order.dto';
import * as orderSchema from './order.schema';
import {
    Subscription,
    SubscriptionDocument,
    SubscriptionStatus,
} from 'src/subscriptions/subscriptions.schema';
import { PaginateOrdersDto } from './dto/paginate-orders.dto';
import { UpdateOrderStatusDto } from './dto/update-order-status.dto';
import { User, UserDocument } from 'src/user/user.schema';
import { PushProducer } from 'src/queue/push.producer';
import { WebPushSubService } from 'src/web-push-sub/web-push-sub.service';
import {
    BillPeriod,
    Product,
    ProductDocument,
} from 'src/products/product.schema';

@Injectable()
export class OrderService {
    constructor(
        @InjectModel(orderSchema.Order.name)
        private readonly orderModel: orderSchema.OrderPaginateModel,
        @InjectModel(Product.name)
        private readonly productModel: Model<ProductDocument>,
        @InjectModel(Subscription.name)
        private readonly subscriptionModel: Model<SubscriptionDocument>,
        @InjectModel(User.name)
        private readonly userModel: Model<UserDocument>,
        private readonly pushProducer: PushProducer,
        private readonly webPushSubService: WebPushSubService,
    ) {}

    async createUserRequestOrder(
        userId: string | Types.ObjectId,
        dto: UserCreateOrderDto,
        idempotencyKey?: string | null,
    ) {
        const userObjectId = new Types.ObjectId(userId);
        const productObjectId = new Types.ObjectId(dto.product);

        // --- 1) Idempotency (same as before) ---
        if (idempotencyKey) {
            const existingByIdem = await this.orderModel
                .findOne({ user: userObjectId, idempotencyKey })
                .lean();
            if (existingByIdem) return existingByIdem;
        }

        // --- 3) Product ---
        const product = await this.productModel.findById(dto.product).lean();
        if (!product) throw new NotFoundException('Product not found');

        const billPeriod = dto.billPeriod;
        const billingMonths = this.mapBillPeriodToMonths(billPeriod);
        const amount = Number(dto.amount);
        if (Number.isNaN(amount) || amount < 0) {
            throw new BadRequestException('Invalid amount');
        }

        // --- 4) TradingView username: conditional requirement ---
        let tradingViewUsername: string | undefined = undefined;

        if (product.requireTradingViewUsername) {
            // for this product TradingView username IS required
            const tv = dto.tradingViewUsername?.trim();
            if (!tv) {
                throw new BadRequestException(
                    'TradingView username is required for this product',
                );
            }
            tradingViewUsername = tv;
        } else {
            // not required; if provided, trim and store, otherwise ignore
            if (typeof dto.tradingViewUsername === 'string') {
                const tv = dto.tradingViewUsername.trim();
                tradingViewUsername = tv.length > 0 ? tv : undefined;
            }
        }

        const initialStatus = dto.status ?? orderSchema.OrderStatus.INIT;
        if (
            ![
                orderSchema.OrderStatus.INIT,
                orderSchema.OrderStatus.PAID,
                orderSchema.OrderStatus.FAILED,
            ].includes(initialStatus)
        ) {
            throw new BadRequestException('Unsupported initial status');
        }

        const shouldEnsureActive =
            initialStatus === orderSchema.OrderStatus.INIT;

        const orderId = this.generateOrderId();
        const nextBill = this.calculateNextBillDate(billingMonths);
        const expiry =
            initialStatus === orderSchema.OrderStatus.PAID
                ? this.calculateExpiry(new Date(), billingMonths)
                : null;
        const subscriptionStatus =
            initialStatus === orderSchema.OrderStatus.PAID
                ? SubscriptionStatus.Active
                : initialStatus === orderSchema.OrderStatus.FAILED
                  ? SubscriptionStatus.Paused
                  : SubscriptionStatus.Pending;

        try {
            const doc = await this.orderModel.create({
                user: userObjectId,
                product: productObjectId,
                status: initialStatus,
                idempotencyKey: idempotencyKey ?? this.generateOrderId(),
                orderId,
                amount,
                billPeriod,
                tradingViewUsername, // <- use the variable we computed above
                bankAccountName: dto.bankAccountName,
                orderedAt: new Date(),
                expiredAt: expiry,
            });

            if (shouldEnsureActive) {
                await this.subscriptionModel.create({
                    user: userObjectId,
                    product: productObjectId,
                    status: subscriptionStatus,
                    billPeriod,
                    nextBill,
                });
            }

            const orderObject = (doc as any).toObject
                ? (doc as any).toObject()
                : doc;

            try {
                const recipients = await this.webPushSubService.getAdminIds();
                if (recipients.length) {
                    const tinyPayload = {
                        title: 'New order request',
                        body: `Order ${orderId} placed by user ${userId}`,
                    };
                    await this.pushProducer.enqueueSendToUsers(
                        recipients,
                        tinyPayload,
                        {
                            ttl: 3600,
                            chunkSize: 500,
                        },
                    );
                }
            } catch (e) {
                console.warn(
                    '[OrderService.createUserRequestOrder] push enqueue failed:',
                    e,
                );
            }

            return orderObject;
        } catch (err: any) {
            // Race condition protection: unique partial index violation
            if (
                err?.code === 11000 &&
                err?.keyPattern?.user &&
                err?.keyPattern?.product
            ) {
                throw new BadRequestException(
                    'You already have an active order for this product.',
                );
            }
            throw err;
        }
    }

    async updateUserOrder(
        orderId: string,
        userId: string | Types.ObjectId,
        dto: UserCreateOrderDto,
    ) {
        if (!Types.ObjectId.isValid(orderId)) {
            throw new NotFoundException('Order not found');
        }
        const userObjectId = new Types.ObjectId(userId);

        const existing = await this.orderModel
            .findOne({ _id: orderId, user: userObjectId })
            .lean();
        if (!existing) {
            throw new NotFoundException('Order not found');
        }
        if (existing.status !== orderSchema.OrderStatus.FAILED) {
            throw new BadRequestException(
                'Only FAILED orders can be reordered.',
            );
        }

        const productObjectId = new Types.ObjectId(dto.product);
        const product = await this.productModel
            .findById(productObjectId)
            .lean();
        if (!product) throw new NotFoundException('Product not found');

        const billPeriod = dto.billPeriod;
        const billingMonths = this.mapBillPeriodToMonths(billPeriod);
        const amount = Number(dto.amount);
        if (Number.isNaN(amount) || amount < 0) {
            throw new BadRequestException('Invalid amount');
        }

        let tradingViewUsername: string | undefined = undefined;
        if (product.requireTradingViewUsername) {
            const tv = dto.tradingViewUsername?.trim();
            if (!tv) {
                throw new BadRequestException(
                    'TradingView username is required for this product',
                );
            }
            tradingViewUsername = tv;
        } else if (typeof dto.tradingViewUsername === 'string') {
            const tv = dto.tradingViewUsername.trim();
            tradingViewUsername = tv.length > 0 ? tv : undefined;
        }

        const nextStatus = dto.status ?? orderSchema.OrderStatus.INIT;
        if (
            ![
                orderSchema.OrderStatus.INIT,
                orderSchema.OrderStatus.PAID,
                orderSchema.OrderStatus.FAILED,
            ].includes(nextStatus)
        ) {
            throw new BadRequestException('Unsupported status');
        }

        const expiry =
            nextStatus === orderSchema.OrderStatus.PAID
                ? this.calculateExpiry(new Date(), billingMonths)
                : null;

        const orderUpdate = {
            product: productObjectId,
            billPeriod,
            amount,
            bankAccountName: dto.bankAccountName,
            tradingViewUsername,
            status: nextStatus,
            expiredAt: expiry,
            orderedAt: new Date(),
        };

        const updated = await this.orderModel
            .findByIdAndUpdate(orderId, orderUpdate, {
                new: true,
                runValidators: true,
            })
            .lean()
            .exec();

        if (!updated) {
            throw new NotFoundException('Order not found');
        }

        const subStatus =
            nextStatus === orderSchema.OrderStatus.PAID
                ? SubscriptionStatus.Active
                : nextStatus === orderSchema.OrderStatus.FAILED
                  ? SubscriptionStatus.Paused
                  : SubscriptionStatus.Pending;

        const nextBill = this.calculateNextBillDate(billingMonths);
        await this.subscriptionModel
            .findOneAndUpdate(
                { user: userObjectId, product: productObjectId },
                {
                    user: userObjectId,
                    product: productObjectId,
                    status: subStatus,
                    billPeriod,
                    nextBill,
                },
                { new: true, upsert: true },
            )
            .lean()
            .exec();

        return updated;
    }

    async paginate(
        dto: PaginateOrdersDto,
    ): Promise<PaginateResult<orderSchema.OrderDocument>> {
        const { q, status, page = 1, limit = 20 } = dto;
        const filter: FilterQuery<orderSchema.OrderDocument> = {};

        if (status) {
            filter.status = status;
        }

        if (q && q.trim()) {
            const trimmed = q.trim();
            const rx = new RegExp(this.escapeRegex(trimmed), 'i');
            const users = await this.userModel
                .find(
                    {
                        $or: [
                            { firstName: rx },
                            { lastName: rx },
                            {
                                $expr: {
                                    $regexMatch: {
                                        input: {
                                            $trim: {
                                                input: {
                                                    $concat: [
                                                        '$firstName',
                                                        ' ',
                                                        {
                                                            $ifNull: [
                                                                '$lastName',
                                                                '',
                                                            ],
                                                        },
                                                    ],
                                                },
                                            },
                                        },
                                        regex: this.escapeRegex(trimmed),
                                        options: 'i',
                                    },
                                },
                            },
                        ],
                    },
                    { _id: 1 },
                )
                .limit(500)
                .lean()
                .exec();

            const userIds = users.map((u) => u._id);
            const orFilters: any[] = [{ bankAccountName: rx }];
            if (userIds.length) {
                orFilters.push({ user: { $in: userIds } });
            }
            filter.$or = orFilters;
        }

        const options: PaginateOptions = {
            page,
            limit,
            sort: { orderedAt: -1 },
            lean: true,
            leanWithId: false,
            populate: [
                { path: 'user', select: '_id firstName lastName email' },
                { path: 'product', select: 'name billPeriod' },
            ],
        };

        return this.orderModel.paginate(filter, options);
    }

    async getUserOrders(
        userId: string | Types.ObjectId,
        opts: {
            productId?: string | Types.ObjectId;
            onlyActive?: boolean;
        } = {},
    ) {
        const userObjectId = new Types.ObjectId(userId);
        const filter: any = { user: userObjectId };
        if (opts.productId) {
            filter.product = new Types.ObjectId(opts.productId);
        }
        if (opts.onlyActive) {
            filter.status = {
                $in: [
                    orderSchema.OrderStatus.INIT,
                    orderSchema.OrderStatus.UNPAID,
                ],
            };
        }
        return this.orderModel.find(filter).sort({ orderedAt: -1 }).lean();
    }

    async getOrderById(orderId: string) {
        if (!Types.ObjectId.isValid(orderId)) {
            throw new NotFoundException('Order not found');
        }

        const order = await this.orderModel
            .findById(orderId)
            .populate('user', '_id firstName lastName email')
            .populate('product', 'name billPeriod')
            .lean()
            .exec();

        if (!order) {
            throw new NotFoundException('Order not found');
        }

        return order;
    }

    async getOrderByUserAndProduct(
        userId: string | Types.ObjectId,
        productId: string | Types.ObjectId,
    ) {
        if (
            !Types.ObjectId.isValid(String(userId)) ||
            !Types.ObjectId.isValid(String(productId))
        ) {
            throw new NotFoundException('Order not found');
        }

        const order = await this.orderModel
            .find({
                user: new Types.ObjectId(userId),
                product: new Types.ObjectId(productId),
            })
            .lean()
            .exec();

        if (!order) {
            throw new NotFoundException('Order not found');
        }

        return order;
    }

    async getOrderBySubscription(subscriptionId: string) {
        if (!Types.ObjectId.isValid(subscriptionId)) {
            throw new NotFoundException('Subscription not found');
        }

        const subscription = await this.subscriptionModel
            .findById(subscriptionId)
            .lean()
            .exec();

        if (!subscription) {
            throw new NotFoundException('Subscription not found');
        }

        const order = await this.orderModel
            .find({
                product: subscription.product,
                user: subscription.user,
            })
            .populate('user', '_id firstName lastName email ')
            .populate(
                'product',
                'name billPeriod requireTradingViewUsername payWayUrls',
            )
            .lean()
            .exec();
        return order;
    }

    async updateOrderStatus(
        orderId: string,
        dto: UpdateOrderStatusDto,
        updatedBy?: string,
    ) {
        if (!Types.ObjectId.isValid(orderId)) {
            throw new NotFoundException('Order not found');
        }

        const existing = await this.orderModel.findById(orderId).lean();
        if (!existing) {
            throw new NotFoundException('Order not found');
        }

        const billMonths = this.mapBillPeriodToMonths(existing.billPeriod);
        const expiry =
            dto.status === orderSchema.OrderStatus.PAID
                ? this.calculateExpiry(
                      existing.orderedAt ?? new Date(),
                      billMonths,
                  )
                : null;

        const updatePayload: any = { status: dto.status, expiredAt: expiry };
        if (updatedBy && Types.ObjectId.isValid(updatedBy)) {
            updatePayload.updatedBy = new Types.ObjectId(updatedBy);
        }

        const updated = await this.orderModel
            .findByIdAndUpdate(orderId, updatePayload, {
                new: true,
                runValidators: true,
            })
            .populate('user', '_id firstName lastName email')
            .populate('product', 'name billPeriod')
            .lean()
            .exec();

        if (!updated) {
            throw new NotFoundException('Order not found');
        }

        const userId = new Types.ObjectId(
            ((updated as any).user?._id ?? (updated as any).user) as string,
        );
        const productId = new Types.ObjectId(
            ((updated as any).product?._id ??
                (updated as any).product) as string,
        );

        let targetStatus: SubscriptionStatus;
        if (dto.status === orderSchema.OrderStatus.PAID) {
            targetStatus = SubscriptionStatus.Active;
        } else if (
            dto.status === orderSchema.OrderStatus.INIT ||
            dto.status === orderSchema.OrderStatus.UNPAID
        ) {
            targetStatus = SubscriptionStatus.Pending;
        } else {
            targetStatus = SubscriptionStatus.Paused;
        }

        const subUpdate: Partial<SubscriptionDocument> = {
            status: targetStatus,
        };
        if (targetStatus === SubscriptionStatus.Active) {
            const nextBill = this.calculateNextBillDate(billMonths);
            (subUpdate as any).nextBill = nextBill;
        }

        await this.subscriptionModel
            .findOneAndUpdate({ user: userId, product: productId }, subUpdate, {
                new: true,
            })
            .lean()
            .exec();

        return updated;
    }

    private generateOrderId(): string {
        const ts = new Date().toISOString().slice(0, 10).replaceAll('-', '');
        const rand = Math.random().toString(36).slice(2, 8).toUpperCase();
        return `ORD-${ts}-${rand}`;
    }

    private calculateNextBillDate(billingPeriod: number): Date {
        if (billingPeriod <= 0) {
            return new Date('9999-12-31T00:00:00.000Z');
        }
        const next = new Date();
        next.setMonth(next.getMonth() + billingPeriod);
        return next;
    }

    private escapeRegex(value: string): string {
        return value.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    }

    private calculateExpiry(startDate: Date, billingPeriod: number): Date {
        if (billingPeriod <= 0) {
            return new Date('9999-12-31T00:00:00.000Z');
        }
        const start = new Date(startDate);
        start.setMonth(start.getMonth() + billingPeriod);
        return start;
    }

    private mapBillPeriodToMonths(period: BillPeriod): number {
        switch (period) {
            case BillPeriod.MONTH:
                return 1;
            case BillPeriod.THREE_MONTHS:
                return 3;
            case BillPeriod.SIX_MONTHS:
                return 6;
            case BillPeriod.YEAR:
                return 12;
            case BillPeriod.LIFETIME:
            case BillPeriod.ONE_TIME:
            default:
                return 0;
        }
    }
}

