// src/queue/push.worker.ts
import { Injectable, Logger } from '@nestjs/common';
import { Processor, WorkerHost } from '@nestjs/bullmq';
import { Job } from 'bullmq';
import { InjectModel } from '@nestjs/mongoose';
import { Model, Types } from 'mongoose';
import {
    WebPushSub,
    WebPushSubDocument,
} from 'src/web-push-sub/web-push-sub.schema';
import { WebPushSubService } from 'src/web-push-sub/web-push-sub.service';

interface FanoutJob {
    contentId: string;
    segment: string;
    ttl?: number;
}
interface SendToUsersJob {
    userIds: string[];
    payload: string;
    ttl?: number;
}

const PAGE_SIZE = 1000;
const PAGE_JITTER_MS: [number, number] = [120, 360];

@Processor('push')
@Injectable()
export class PushWorker extends WorkerHost {
    private readonly log = new Logger(PushWorker.name);

    constructor(
        private readonly webPushSubSvc: WebPushSubService,
        @InjectModel(WebPushSub.name)
        private readonly subModel: Model<WebPushSubDocument>,
    ) {
        super();
    }

    // BullMQ entrypoint — no @Process decorator in @nestjs/bullmq
    async process(job: Job<any>): Promise<any> {
        switch (job.name) {
            case 'sendToUsers':
                return this.handleSendToUsers(job as Job<SendToUsersJob>);
            case 'fanout':
                return this.handleFanout(job as Job<FanoutJob>);
            default:
                this.log.warn(`Unknown job: ${job.name}`);
                return { ok: true };
        }
    }

    private async handleSendToUsers(job: Job<SendToUsersJob>) {
        const { userIds, payload, ttl = 60 } = job.data;
        if (!Array.isArray(userIds) || userIds.length === 0) {
            this.log.warn(`sendToUsers: empty userIds (jobId=${job.id})`);
            return { ok: true, failed: 0, errors: [] };
        }

        const ids = userIds.map((id) => new Types.ObjectId(id));
        const res = await this.webPushSubSvc.sendToUsers(ids, payload, ttl);
        if (res.failed > 0) {
            this.log.warn(
                `sendToUsers: ${res.failed} failures out of ${ids.length} (jobId=${job.id})`,
            );
        } else {
            this.log.log(
                `sendToUsers: sent to ${ids.length} users (jobId=${job.id})`,
            );
        }
        return res;
    }

    private async handleFanout(job: Job<FanoutJob>) {
        const { contentId, segment, ttl = 3600 } = job.data;
        const tiny = { id: contentId };

        const total = await this.subModel.countDocuments({
            active: true,
            segments: segment,
        });
        let sent = 0,
            failed = 0;
        let lastId: Types.ObjectId | null = null;

        while (true) {
            const q: any = { active: true, segments: segment };
            if (lastId) q._id = { $gt: lastId };

            const page = await this.subModel
                .find(q)
                .sort({ _id: 1 })
                .limit(PAGE_SIZE)
                .select({ userId: 1 })
                .lean()
                .exec();

            if (!page.length) break;
            lastId = page[page.length - 1]._id;

            const ids = Array.from(
                new Set(page.map((s) => String(s.userId))),
            ).map((id) => new Types.ObjectId(id));

            const res = await this.webPushSubSvc.sendToUsers(ids, '', ttl);
            sent += ids.length - res.failed;
            failed += res.failed;

            const [min, max] = PAGE_JITTER_MS;
            await new Promise((r) =>
                setTimeout(r, Math.floor(min + Math.random() * (max - min))),
            );
        }

        if (failed > 0) {
            this.log.warn(
                `fanout: segment="${segment}" total=${total} sent=${sent} failed=${failed} (jobId=${job.id})`,
            );
        } else {
            this.log.log(
                `fanout: segment="${segment}" total=${total} sent=${sent} (jobId=${job.id})`,
            );
        }
        return { ok: failed === 0, failed, errors: [] };
    }
}

// src/real-time/realtime.gateway.ts
import {
    WebSocketGateway,
    WebSocketServer,
    SubscribeMessage,
    MessageBody,
    ConnectedSocket,
    OnGatewayConnection,
    OnGatewayDisconnect,
} from '@nestjs/websockets';
import { Logger, UsePipes, ValidationPipe } from '@nestjs/common';
import { Server, Socket } from 'socket.io';
import { IsString } from 'class-validator';

// --- DTOs ---
class JoinRoomDto {
    @IsString()
    room!: string;
}
class LeaveRoomDto {
    @IsString()
    room!: string;
}

@WebSocketGateway({ namespace: '/realtime' })
export class RealtimeGateway
    implements OnGatewayConnection, OnGatewayDisconnect
{
    @WebSocketServer() io!: Server;
    private readonly logger = new Logger(RealtimeGateway.name);

    handleConnection(client: Socket) {
        const userId = client.handshake.auth?.userId as string | undefined;
        if (userId) {
            client.data.userId = userId;
            client.join(`user:${userId}`);
        }
        this.logger.log(
            `WS connected id=${client.id} user=${userId ?? 'anon'}`,
        );
    }

    handleDisconnect(client: Socket) {
        this.logger.log(`WS disconnected id=${client.id}`);
    }

    @SubscribeMessage('ping')
    ping(@ConnectedSocket() client: Socket, @MessageBody() data?: unknown) {
        client.emit('pong', { at: Date.now(), echo: data ?? null });
    }

    @UsePipes(new ValidationPipe({ whitelist: true, transform: true }))
    @SubscribeMessage('join')
    onJoin(@ConnectedSocket() client: Socket, @MessageBody() dto: JoinRoomDto) {
        client.join(dto.room);
        client.emit('joined', { room: dto.room });
    }

    @UsePipes(new ValidationPipe({ whitelist: true, transform: true }))
    @SubscribeMessage('leave')
    onLeave(
        @ConnectedSocket() client: Socket,
        @MessageBody() dto: LeaveRoomDto,
    ) {
        client.leave(dto.room);
        client.emit('left', { room: dto.room });
    }

    // === Helpers (call from services) ===
    publishBadge(tabId: string) {
        this.io.emit('content:published', { id: tabId, at: Date.now() });
    }

    emitToRoom(room: string, event: string, payload: unknown) {
        this.io.to(room).emit(event, payload);
    }

    notifyUser(userId: string, event: string, payload: unknown) {
        this.io.to(`user:${userId}`).emit(event, payload);
    }
}

import { IoAdapter } from '@nestjs/platform-socket.io';
import type { INestApplicationContext, LoggerService } from '@nestjs/common';
import { Logger } from '@nestjs/common';
import type { ServerOptions } from 'socket.io';
import { createAdapter } from '@socket.io/redis-adapter';
import type { Redis } from 'ioredis';
import IORedis from 'ioredis';

export class SocketIoAdapter extends IoAdapter {
    private readonly logger: LoggerService;
    private pubClient: Redis | null = null;
    private subClient: Redis | null = null;

    constructor(
        app: INestApplicationContext,
        private readonly allowedOrigins: string[],
    ) {
        super(app);
        this.logger = new Logger(SocketIoAdapter.name);
    }

    async connectToRedisIfNeeded() {
        if (this.pubClient && this.subClient) return;

        const url = process.env.REDIS_URL;
        if (!url) {
            this.logger.warn(
                'Running WITHOUT Redis adapter (single instance only)',
            );
            return;
        }

        const createClient = () => {
            const client = new IORedis(url, {
                lazyConnect: true,
                maxRetriesPerRequest: null,
                enableReadyCheck: true,
                retryStrategy: () => null,
            });

            client.on('error', (error) => {
                this.logger.warn(
                    `Socket.IO Redis unavailable: ${error.message}`,
                );
            });

            return client;
        };

        const pubClient = createClient();
        const subClient = createClient();

        try {
            await Promise.all([pubClient.connect(), subClient.connect()]);
            this.pubClient = pubClient;
            this.subClient = subClient;
            this.logger.log(`Socket.IO Redis adapter connected (${url})`);
        } catch (error) {
            pubClient.disconnect();
            subClient.disconnect();
            this.logger.warn(
                `Running WITHOUT Redis adapter (${error instanceof Error ? error.message : String(error)})`,
            );
        }
    }

    override createIOServer(port: number, options?: ServerOptions) {
        const server = super.createIOServer(port, {
            ...options,
            cors: {
                origin: this.allowedOrigins,
                credentials: true,
                methods: ['GET', 'POST', 'OPTIONS'],
                allowedHeaders: [
                    'content-type',
                    'accept',
                    'authorization',
                    'x-csrf-token',
                    'x-client-device-id',
                    'x-device-id',
                    'x-device-hash',
                    'x-internal-signature',
                    'x-internal-timestamp',
                    'x-idempotency-key',
                    'idempotency-key',
                ],
            },
            transports: ['websocket', 'polling'],
            allowRequest: (req, fn) => {
                const origin = (req.headers.origin as string | undefined) ?? '';
                // Option A (safer, but allows non-browser clients): allow when Origin is missing
                const allowWhenNoOrigin = true;

                const ok = origin
                    ? this.allowedOrigins.includes(origin)
                    : allowWhenNoOrigin;

                if (!ok) {
                    this.logger.warn(`WS blocked origin=${origin || 'none'}`);
                    // IMPORTANT: pass a STRING to engine.io, not an Error object
                    return fn('Origin not allowed', false);
                }
                return fn(null, true);
            },
        });

        if (this.pubClient && this.subClient) {
            // @ts-ignore
            server.adapter(createAdapter(this.pubClient, this.subClient));
            this.logger.log('Socket.IO Redis adapter enabled');
        }

        return server;
    }
}

