type UploadBufferOptions = {
    key: string;
    buffer: Buffer;
    contentType?: string;
    acl?: 'private' | 'public-read';
    cacheControl?: string;
};

type UploadFileOptions = {
    folder?: string;
    acl?: 'private' | 'public-read';
    cacheControl?: string;
    key?: string;
};

type UploadFromUrlOptions = {
    folder?: string;
    filename?: string;
    acl?: 'private' | 'public-read';
    cacheControl?: string;
};

@Injectable()
export class AwsS3Service {
    private readonly region: string;
    private readonly bucket: string;
    private readonly accessKey: string;
    private readonly secretKey: string;

    constructor(private readonly config: ConfigService) {
        this.region = this.config.get<string>('AWS_REGION', 'ap-southeast-2');
        this.bucket = this.config.get<string>('S3_BUCKET_NAME', '');
        this.accessKey = this.config.get<string>('AWS_ACCESS_KEY_ID', '');
        this.secretKey = this.config.get<string>('AWS_SECRET_ACCESS_KEY', '');

        if (!this.bucket || !this.accessKey || !this.secretKey) {
            throw new Error(
                'AWS credentials or bucket name are not configured',
            );
        }
    }

    async uploadFile(
        file: UploadedFile,
        opts?: UploadFileOptions,
    ): Promise<UploadResult> {
        if (!file?.buffer?.length) {
            throw new InternalServerErrorException('File buffer is empty');
        }

        const folder = (opts?.folder ?? 'uploads')
            .replace(/^\/*/, '')
            .replace(/\/*$/, '');
        const safeOriginal = (file.originalname || 'file').replace(
            /[^\w.\-]+/g,
            '-',
        );
        const key =
            opts?.key ??
            `${folder}/${new Date().toISOString().slice(0, 10)}/${Date.now()}-${randomUUID()}-${safeOriginal}`;

        return this.uploadBuffer({
            key,
            buffer: file.buffer,
            contentType: file.mimetype,
            acl: opts?.acl,
            cacheControl: opts?.cacheControl,
        });
    }

    async uploadBuffer(options: UploadBufferOptions): Promise<UploadResult> {
        const { key, buffer, contentType, acl, cacheControl } = options;
        if (!buffer?.length) {
            throw new InternalServerErrorException('Upload buffer is empty');
        }

        const host = `${this.bucket}.s3.${this.region}.amazonaws.com`;
        const encodedKey = key
            .split('/')
            .map((segment) => encodeURIComponent(segment))
            .join('/');
        const url = `https://${host}/${encodedKey}`;

        const now = new Date();
        const amzDate = this.formatAmzDate(now);
        const dateStamp = amzDate.slice(0, 8);
        const payloadHash = this.sha256Hex(buffer);

        const headers: Record<string, string> = {
            host,
            'x-amz-content-sha256': payloadHash,
            'x-amz-date': amzDate,
        };

        if (contentType) headers['content-type'] = contentType;
        if (cacheControl) headers['cache-control'] = cacheControl;
        if (acl) headers['x-amz-acl'] = acl;

        const canonicalHeaders = this.buildCanonicalHeaders(headers);
        const signedHeaders = Object.keys(canonicalHeaders).join(';');
        const canonicalHeadersString = Object.entries(canonicalHeaders)
            .map(([name, value]) => `${name}:${value}\n`)
            .join('');

        const canonicalRequest = [
            'PUT',
            `/${encodedKey}`,
            '',
            canonicalHeadersString,
            signedHeaders,
            payloadHash,
        ].join('\n');

        const credentialScope = `${dateStamp}/${this.region}/s3/aws4_request`;
        const stringToSign = [
            'AWS4-HMAC-SHA256',
            amzDate,
            credentialScope,
            this.sha256Hex(Buffer.from(canonicalRequest, 'utf8')),
        ].join('\n');

        const signingKey = this.getSignatureKey(
            this.secretKey,
            dateStamp,
            this.region,
            's3',
        );
        const signature = createHmac('sha256', signingKey)
            .update(stringToSign)
            .digest('hex');

        headers.authorization = [
            `AWS4-HMAC-SHA256 Credential=${this.accessKey}/${credentialScope}`,
            `SignedHeaders=${signedHeaders}`,
            `Signature=${signature}`,
        ].join(', ');

        const response = await fetch(url, {
            method: 'PUT',
            headers,
            body: new Uint8Array(buffer),
        });

        if (!response.ok) {
            const text = await response.text().catch(() => 'Unknown error');
            throw new InternalServerErrorException(
                `Failed to upload to S3 (${response.status}): ${text}`,
            );
        }

        return { key, url };
    }

    async uploadFromUrl(
        sourceUrl: string,
        opts?: UploadFromUrlOptions,
    ): Promise<UploadResult> {
        const response = await fetch(sourceUrl);
        if (!response.ok || !response.body) {
            throw new InternalServerErrorException(
                `Failed to download file (${response.status} ${response.statusText})`,
            );
        }

        const arrayBuffer = await response.arrayBuffer();
        const buffer = Buffer.from(arrayBuffer);
        const contentType = response.headers.get('content-type') ?? undefined;

        const folder = (opts?.folder ?? 'uploads')
            .replace(/^\/*/, '')
            .replace(/\/*$/, '');
        const filename =
            opts?.filename ??
            sourceUrl
                .split('/')
                .pop()
                ?.split('?')[0]
                ?.replace(/[^\w.\-]+/g, '-') ??
            `remote-${randomUUID()}`;

        const key = `${folder}/${new Date().toISOString().slice(0, 10)}/${Date.now()}-${filename}`;

        return this.uploadBuffer({
            key,
            buffer,
            contentType,
            acl: opts?.acl,
            cacheControl: opts?.cacheControl,
        });
    }

    async deleteFileByKey(key: string): Promise<void> {
        if (!key) return;

        const host = `${this.bucket}.s3.${this.region}.amazonaws.com`;
        const encodedKey = key
            .split('/')
            .map((segment) => encodeURIComponent(segment))
            .join('/');
        const url = `https://${host}/${encodedKey}`;

        const now = new Date();
        const amzDate = this.formatAmzDate(now);
        const dateStamp = amzDate.slice(0, 8);
        const payloadHash = this.sha256Hex(Buffer.from(''));

        const headers: Record<string, string> = {
            host,
            'x-amz-content-sha256': payloadHash,
            'x-amz-date': amzDate,
        };

        const canonicalHeaders = this.buildCanonicalHeaders(headers);
        const signedHeaders = Object.keys(canonicalHeaders).join(';');
        const canonicalHeadersString = Object.entries(canonicalHeaders)
            .map(([name, value]) => `${name}:${value}\n`)
            .join('');

        const canonicalRequest = [
            'DELETE',
            `/${encodedKey}`,
            '',
            canonicalHeadersString,
            signedHeaders,
            payloadHash,
        ].join('\n');

        const credentialScope = `${dateStamp}/${this.region}/s3/aws4_request`;
        const stringToSign = [
            'AWS4-HMAC-SHA256',
            amzDate,
            credentialScope,
            this.sha256Hex(Buffer.from(canonicalRequest, 'utf8')),
        ].join('\n');

        const signingKey = this.getSignatureKey(
            this.secretKey,
            dateStamp,
            this.region,
            's3',
        );
        const signature = createHmac('sha256', signingKey)
            .update(stringToSign)
            .digest('hex');

        headers.authorization = [
            `AWS4-HMAC-SHA256 Credential=${this.accessKey}/${credentialScope}`,
            `SignedHeaders=${signedHeaders}`,
            `Signature=${signature}`,
        ].join(', ');

        const response = await fetch(url, {
            method: 'DELETE',
            headers,
        });

        if (!response.ok) {
            const text = await response.text().catch(() => 'Unknown error');
            throw new InternalServerErrorException(
                `Failed to delete from S3 (${response.status}): ${text}`,
            );
        }
    }

    async deleteFileByUrl(fileUrl: string): Promise<boolean> {
        const key = this.getKeyFromUrl(fileUrl);
        if (!key) return false;
        await this.deleteFileByKey(key);
        return true;
    }

    getPublicUrl(key: string): string {
        const encodedKey = key
            .split('/')
            .map((segment) => encodeURIComponent(segment))
            .join('/');
        return `https://${this.bucket}.s3.${this.region}.amazonaws.com/${encodedKey}`;
    }

    private formatAmzDate(date: Date): string {
        const iso = date.toISOString(); // e.g., 2025-01-17T10:24:30.123Z
        return iso.replace(/[-:]/g, '').replace(/\.\d{3}Z$/, 'Z'); // 20250117T102430Z
    }

    private sha256Hex(data: Buffer): string {
        return createHash('sha256').update(data).digest('hex');
    }

    private getSignatureKey(
        key: string,
        dateStamp: string,
        region: string,
        service: string,
    ) {
        const kDate = createHmac('sha256', `AWS4${key}`)
            .update(dateStamp)
            .digest();
        const kRegion = createHmac('sha256', kDate).update(region).digest();
        const kService = createHmac('sha256', kRegion).update(service).digest();
        return createHmac('sha256', kService).update('aws4_request').digest();
    }

    private buildCanonicalHeaders(
        headers: Record<string, string>,
    ): Record<string, string> {
        return Object.keys(headers)
            .sort()
            .reduce<Record<string, string>>((acc, key) => {
                acc[key.toLowerCase()] = headers[key]
                    .trim()
                    .replace(/\s+/g, ' ');
                return acc;
            }, {});
    }

    private getKeyFromUrl(fileUrl: string): string | null {
        if (!fileUrl) return null;
        try {
            const u = new URL(fileUrl);
            const host = u.hostname;
            const bucketHost = `${this.bucket}.s3.${this.region}.amazonaws.com`;
            const bucketHostAlt = `${this.bucket}.s3.amazonaws.com`;
            const regionalHost = `s3.${this.region}.amazonaws.com`;
            const globalHost = 's3.amazonaws.com';

            const path = decodeURIComponent(u.pathname.replace(/^\/+/, ''));

            if (host === bucketHost || host === bucketHostAlt) {
                return path || null;
            }

            if (host === regionalHost || host === globalHost) {
                if (!path.startsWith(`${this.bucket}/`)) return null;
                return path.slice(this.bucket.length + 1) || null;
            }
        } catch {
            return null;
        }

        return null;
    }
}

import {
    IsEnum,
    IsOptional,
    IsString,
    Length,
    Matches,
    MaxLength,
    IsUrl,
} from 'class-validator';
import { Direction, Pair } from '../trading-plan.enum';

export class CreateTradingPlanDto {
    @IsEnum(Pair)
    pair!: Pair;

    @IsEnum(Direction)
    direction!: Direction;

    @IsString()
    @IsOptional()
    @MaxLength(2000)
    description?: string;

    @IsOptional()
    @IsString()
    tradingViewId?: string; // ✅ now optional

    /** Optional thumbnail (e.g., Cloudinary/S3 URL) */
    @IsOptional()
    @IsUrl({ require_tld: false })
    @MaxLength(500)
    thumbnailUrl?: string;
}

// src/trading-plans/trading-plan.controller.ts
import {
    Body,
    Controller,
    Delete,
    Get,
    HttpCode,
    HttpStatus,
    Param,
    Patch,
    Post,
    Req,
    UnauthorizedException,
    UsePipes,
    ValidationPipe,
} from '@nestjs/common';
import { Throttle } from '@nestjs/throttler';
import { TradingPlanService } from './trading-plan.service';
import { CreateTradingPlanDto } from './dto/create-trading-plan.dto';
import type { AuthRequest } from 'src/common/types/auth-request.type';
import { ApiSuccess } from 'src/common/types/api-response.type';
import { Role } from 'src/user/user.enum';
import { Roles } from 'src/auth/decorators/roles.decorator';

@Controller('trading-plan')
export class TradingPlanController {
    constructor(private readonly service: TradingPlanService) {}

    @Post()
    @Roles(Role.Creator, Role.Admin)
    @HttpCode(HttpStatus.CREATED)
    @Throttle({ default: { limit: 5, ttl: 30_000 } })
    async create(
        @Req() req: AuthRequest,
        @Body() dto: CreateTradingPlanDto,
    ): Promise<ApiSuccess<unknown>> {
        const uid = req?.user?.userId;
        if (!uid) throw new UnauthorizedException('AUTH_REQUIRED');
        const plan = await this.service.create(uid, dto);
        return {
            success: true,
            statusCode: HttpStatus.CREATED,
            timestamp: new Date().toISOString(),
            path: req.url,
            code: 'CREATE_TRADING_PLAN',
            message: 'Success!',
            data: plan,
        };
    }

    @Get()
    @HttpCode(HttpStatus.OK)
    async findMine(@Req() req: AuthRequest): Promise<ApiSuccess<unknown[]>> {
        const items = await this.service.findAll();

        return {
            success: true,
            statusCode: HttpStatus.OK,
            timestamp: new Date().toISOString(),
            path: req.url,
            code: 'LIST_TRADING_PLANS',
            message: 'Success!',
            data: items,
        };
    }

    @Get(':id')
    @HttpCode(HttpStatus.OK)
    async findOne(
        @Req() req: AuthRequest,
        @Param('id') id: string,
    ): Promise<ApiSuccess<unknown>> {
        const uid = req?.user?.userId;
        if (!uid) throw new UnauthorizedException('AUTH_REQUIRED');

        const plan = await this.service.findById(id);

        return {
            success: true,
            statusCode: HttpStatus.OK,
            timestamp: new Date().toISOString(),
            path: req.url,
            code: 'GET_TRADING_PLAN',
            message: 'Success!',
            data: plan,
        };
    }

    @Patch(':id')
    @Roles(Role.Creator, Role.Admin)
    @HttpCode(HttpStatus.OK)
    @UsePipes(
        new ValidationPipe({ whitelist: true, forbidNonWhitelisted: true }),
    )
    async update(
        @Req() req: AuthRequest,
        @Param('id') id: string,
        @Body() dto: CreateTradingPlanDto,
    ): Promise<ApiSuccess<unknown>> {
        const uid = req?.user?.userId;
        if (!uid) throw new UnauthorizedException('AUTH_REQUIRED');

        const plan = await this.service.update(id, dto);
        return {
            success: true,
            statusCode: HttpStatus.OK,
            timestamp: new Date().toISOString(),
            path: req.url,
            code: 'UPDATE_TRADING_PLAN',
            message: 'Success!',
            data: plan,
        };
    }

    @Delete(':id')
    @Roles(Role.Creator, Role.Admin)
    async remove(@Param('id') id: string, @Req() req: any) {
        return this.service.remove(id);
    }
}

// src/trading-plans/trading-plan.service.ts
import {
    BadRequestException,
    Injectable,
    NotFoundException,
} from '@nestjs/common';
import { InjectModel } from '@nestjs/mongoose';
import { Model, Types } from 'mongoose';

import { TradingPlan, TradingPlanDocument } from './trading-plan.schema';
import { CreateTradingPlanDto } from './dto/create-trading-plan.dto';
import { WebPushSubService } from 'src/web-push-sub/web-push-sub.service';
import { TradingPlanLean } from 'src/common/types/trading.type';
import { RealtimeGateway } from 'src/real-time/realtime.gateway';
import { PushProducer } from 'src/queue/push.producer';

const MAX_PLANS_PER_USER = 6;

@Injectable()
export class TradingPlanService {
    constructor(
        @InjectModel(TradingPlan.name)
        private readonly planModel: Model<TradingPlanDocument>,
        private readonly realtime: RealtimeGateway,
        private readonly pushProducer: PushProducer, // +++
        private readonly webPushSubService: WebPushSubService,
    ) {}

    async create(currentUserId: string, dto: CreateTradingPlanDto) {
        const userId = this.asObjectId(currentUserId);
        let created!: TradingPlanLean;

        const session = await this.planModel.db.startSession();
        try {
            await session.withTransaction(async () => {
                const count = await this.planModel
                    .countDocuments({ publishedBy: userId })
                    .session(session);

                const toDelete = Math.max(0, count - MAX_PLANS_PER_USER + 1);
                if (toDelete > 0) {
                    const oldest = await this.planModel
                        .find({ publishedBy: userId })
                        .sort({ createdAt: 1 })
                        .limit(toDelete)
                        .select({ _id: 1 })
                        .lean()
                        .session(session);

                    const ids = oldest.map((d) => d._id);
                    if (ids.length) {
                        await this.planModel
                            .deleteMany({ _id: { $in: ids } })
                            .session(session);
                    }
                }

                const [doc] = await this.planModel.create(
                    [{ ...dto, publishedBy: userId }],
                    { session },
                );

                created = await this.planModel
                    .findById(doc._id)
                    .lean<TradingPlanLean>()
                    .session(session)
                    .orFail();
            });
        } catch (err: any) {
            if (
                String(err?.message || '').includes(
                    'Transaction numbers are only allowed on a replica set',
                )
            ) {
                const count = await this.planModel.countDocuments({
                    publishedBy: userId,
                });
                const toDelete = Math.max(0, count - MAX_PLANS_PER_USER + 1);
                if (toDelete > 0) {
                    const oldest = await this.planModel
                        .find({ publishedBy: userId })
                        .sort({ createdAt: 1 })
                        .limit(toDelete)
                        .select({ _id: 1 })
                        .lean();

                    const ids = oldest.map((d) => d._id);
                    if (ids.length) {
                        await this.planModel.deleteMany({ _id: { $in: ids } });
                    }
                }

                const doc = await this.planModel.create({
                    ...dto,
                    publishedBy: userId,
                });
                created = await this.planModel
                    .findById(doc._id)
                    .lean<TradingPlanLean>()
                    .orFail();
            } else {
                throw err;
            }
        } finally {
            session.endSession();
        }

        // ---- Push notification (tiny payload; SW will fetch full content by id) ----
        try {
            const tinyPayload = {
                title: 'New Trading Plan 📈',
                body: `${created.pair} • ${created.direction}`,
            };

            // Exclude author if provided on dto (optional)
            let excludeId: Types.ObjectId | null = null;
            const maybeAuthorId = (dto as any)?.authorId;
            if (maybeAuthorId) {
                try {
                    excludeId = new Types.ObjectId(String(maybeAuthorId));
                } catch {
                    /* ignore bad id */
                }
            }

            // Get recipients (all active users, optionally excluding author).
            const recipients = await this.webPushSubService.getUserIdsExcept(
                excludeId ?? new Types.ObjectId('000000000000000000000000'), // excludes no one if author unknown
            );

            if (recipients.length) {
                await this.pushProducer.enqueueSendToUsers(
                    recipients,
                    tinyPayload,
                    { ttl: 3600, chunkSize: 500 },
                );
            }
        } catch (e) {
            // Don’t block creation on push failures
            console.warn('[TradingPlan.create] push enqueue failed:', e);
        }
        // ---------------------------------------------------------------

        return created;
    }

    async findAll() {
        return this.planModel.find({}).sort({ createdAt: -1 }).lean();
    }

    async findById(id: string) {
        if (!Types.ObjectId.isValid(id)) {
            throw new BadRequestException('Invalid trading plan id');
        }

        const doc = await this.planModel
            .findById(id)
            .populate({
                path: 'publishedBy',
                select: 'firstName lastName -_id',
            }) // <- only these fields
            .lean();

        if (!doc) {
            throw new NotFoundException('Trading plan not found');
        }

        return doc;
    }

    async remove(planId: string) {
        if (!Types.ObjectId.isValid(planId)) {
            throw new BadRequestException('Invalid trading plan id');
        }

        // Atomic: match by _id + publishedBy
        const deleted = await this.planModel
            .findOneAndDelete({ _id: planId })
            .lean();

        if (!deleted) {
            // Either it didn’t exist, or it wasn’t owned by this user
            throw new NotFoundException('Trading plan not found');
        }

        return { ok: true, id: String(deleted._id) };
    }

    async update(planId: string, dto: CreateTradingPlanDto) {
        if (!Types.ObjectId.isValid(planId)) {
            throw new BadRequestException('Invalid trading plan id');
        }

        const updated = await this.planModel
            .findByIdAndUpdate(
                planId,
                {
                    pair: dto?.pair,
                    direction: dto?.direction,
                    description: dto?.description,
                    thumbnailUrl: dto?.thumbnailUrl,
                    tradingViewId: dto?.tradingViewId,
                },
                { new: true, runValidators: true },
            )
            .lean<TradingPlanLean>()
            .exec();

        if (!updated) {
            throw new NotFoundException('Trading plan not found');
        }

        // Optional: publish any badges/updates on edit as well
        this.realtime.publishBadge('trading-plans');

        return updated;
    }

    // --- helpers ---
    private asObjectId(id: string) {
        if (!Types.ObjectId.isValid(id)) {
            throw new BadRequestException('Invalid user id');
        }
        return new Types.ObjectId(id);
    }
}

// src/turnstile/turnstile.guard.ts
import {
    Injectable,
    CanActivate,
    ExecutionContext,
    BadRequestException,
} from '@nestjs/common';
import { Reflector } from '@nestjs/core';
import { TURNSTILE_ACTION } from './turnstile.decorator';
import { TurnstileService } from './turnstile.service';

@Injectable()
export class TurnstileGuard implements CanActivate {
    constructor(
        private readonly turnstile: TurnstileService,
        private readonly reflector: Reflector,
    ) {}

    async canActivate(ctx: ExecutionContext) {
        const req = ctx.switchToHttp().getRequest();

        const token =
            req.body?.['cf-turnstile-response']?.toString() ??
            req.body?.turnstileToken?.toString();

        if (!token) throw new BadRequestException('Missing Turnstile token');

        const expectedAction =
            this.reflector.get<string>(TURNSTILE_ACTION, ctx.getHandler()) ??
            this.reflector.get<string>(TURNSTILE_ACTION, ctx.getClass());

        const ip =
            req.headers['cf-connecting-ip'] ||
            req.headers['x-forwarded-for'] ||
            req.ip;

        await this.turnstile.verify(token, String(ip || ''), expectedAction);
        return true;
    }
}

// src/user/users.controller.ts
import {
    BadRequestException,
    Body,
    Controller,
    Delete,
    Get,
    HttpCode,
    Param,
    Patch,
    Query,
    Req,
    UnauthorizedException,
} from '@nestjs/common';
import { UserService } from './user.service';
import { UserQueryDto } from './dto/user-query.dto';
import { AdminSetPasswordDto } from './dto/admin-set-password.dto';
import { isValidObjectId } from 'mongoose';
import { UpdateUserRoleDto } from './dto/update-user-role.dto';
import { Roles } from 'src/auth/decorators/roles.decorator';
import { Role } from './user.enum';

@Controller('user')
export class UsersController {
    constructor(private readonly service: UserService) {}

    @Get()
    @Roles(Role.Admin)
    list(@Query() query: UserQueryDto) {
        return this.service.paginate(query);
    }

    @Delete(':id')
    @Roles(Role.Admin)
    async deleteUser(@Param('id') id: string): Promise<void> {
        await this.service.deleteById(id);
    }

    @Patch(':id/password')
    @Roles(Role.Admin)
    async adminSetPassword(
        @Param('id') id: string,
        @Body() dto: AdminSetPasswordDto,
    ) {
        if (!isValidObjectId(id))
            throw new BadRequestException('Invalid user id');
        await this.service.adminSetPassword(id, dto);
        return { ok: true };
    }

    @Patch(':id/role')
    @Roles(Role.Admin)
    async updateRole(
        @Param('id') targetUserId: string,
        @Body() dto: UpdateUserRoleDto,
        @Req() req: any, // assuming req.user is populated by auth guard
    ) {
        if (!isValidObjectId(targetUserId)) {
            throw new BadRequestException('Invalid user id');
        }

        await this.service.updateRole({
            targetUserId,
            newRole: dto.role,
            actingUserId: req?.user?._id, // may be undefined if no auth yet
            actingUserRole: req?.user?.role, // may be undefined if no auth yet
        });

        return { ok: true };
    }
}

